    battery_cutoff_voltage: "battery_under_voltage",
    battery_under_voltage: "battery_under_voltage",

    back_to_grid_voltage: "battery_recharge_voltage",
    battery_recharge_voltage: "battery_recharge_voltage",

    back_to_battery_voltage: "battery_re_discharge_voltage",
    battery_re_discharge_voltage: "battery_re_discharge_voltage",

    max_charging_current: "max_charging_current",

    grid_charging_current: "max_ac_charging_current",
    max_ac_charging_current: "max_ac_charging_current",

    charger_source_priority: "charger_source_priority",
    output_source_priority: "output_source_priority"
  };

  return map[s] || s;
}

function isLearnableParam(p) {
  const lp = canonLearnParam(p);
  return [
    "battery_bulk_voltage",
    "battery_float_voltage",
    "battery_under_voltage",
    "battery_recharge_voltage",
    "battery_re_discharge_voltage",
    "max_charging_current",
    "max_ac_charging_current",
    "charger_source_priority",
    "output_source_priority"
  ].includes(lp);
}

// -------------------------------------------------
// Priorités -> slot canonique interne
// On ne travaille PAS sur les labels ensuite.
// output_source_priority -> slots 0 / 1 / 2
// charger_source_priority -> slots 0 / 1 / 2
// -------------------------------------------------
function normKey(v) {
  return cleanString(v)
    .toLowerCase()
    .replace(/\s+/g, "")
    .replace(/\+/g, "plus");
}

function getOutputPrioritySlot(v) {
  const raw = cleanString(v);
  const key = normKey(v);

  if (raw === "0" || key === "0") return 0;
  if (raw === "1" || key === "1") return 1;
  if (raw === "2" || key === "2") return 2;

  const map = {
    utilitysolarbat: 0,
    usb: 0,

    solarutilitybat: 1,
    sub: 1,

    solarbatutility: 2,
    sbu: 2
  };

  return Number.isInteger(map[key]) ? map[key] : null;
}

function getChargerPrioritySlot(v) {
  const raw = cleanString(v);
  const key = normKey(v);

  if (raw === "0" || key === "0") return 0;
  if (raw === "1" || key === "1") return 1;
  if (raw === "2" || key === "2") return 2;

  const map = {
    solarfirst: 0,
    cso: 0,

    solarplusutility: 1,
    solarutility: 1,
    snu: 1,

    onlysolar: 2,
    oso: 2
  };

  return Number.isInteger(map[key]) ? map[key] : null;
}

// -------------------------------------------------
// RAW COMMAND MANUELLE
// -------------------------------------------------
if (param === "raw_command") {
  const cmd = cleanString(v).toUpperCase();
  if (!cmd) return null;

  const rawMsg = mk(cmd, {
    _burst: false,
    _origin: "ha_set",
    _raw_manual: true,
    _raw_command: cmd
  });

  node.status({
    fill: "yellow",
    shape: "dot",
    text: `RAW ${cmd}`
  });

  return [null, [rawMsg]];
}

// -------------------------------------------------
// PARAMÈTRES APPRENABLES
// -------------------------------------------------
if (isLearnableParam(param)) {
  const learnParam = canonLearnParam(param);

  let learnValue = v;
  let learnMode = "number";

  if (learnParam === "output_source_priority") {
    const slot = getOutputPrioritySlot(v);
    if (slot == null) return null;
    learnValue = slot;
    learnMode = "enum_profile";
  }

  if (learnParam === "charger_source_priority") {
    const slot = getChargerPrioritySlot(v);
    if (slot == null) return null;
    learnValue = slot;
    learnMode = "enum_profile";
  }

  const learnMsg = {
    inverterNum,
    topic: msg.topic,
    payload: learnValue,
    _origin: "ha_set",
    _ha_param: learnParam,
    _ha_param_raw: param,
    _ha_value: learnValue,
    _ha_value_raw: v,
    _learn_mode: learnMode
  };

  node.status({
    fill: "blue",
    shape: "dot",
    text: `LEARN ${learnParam}`
  });

  return [learnMsg, null];
}

// -------------------------------------------------
// Tables de mapping direct (hors apprentissage)
// -------------------------------------------------
const batteryTypeMap = {
  AGM: "PBT00",
  Flooded: "PBT01",
  User: "PBT02",
  Pylon: "PBT03",
  Weco: "PBT05",
  Soltaro: "PBT06",
  Lib: "PBT08",
  Lic: "PBT09"
};

// -------------------------------------------------
// Résolution commande directe
// -------------------------------------------------
const machine = getParallelId(inverterNum);

let cmd = null;
let refresh = ["QMOD", "QPIGS"];

if (param === "battery_type") {
  const sv = cleanString(v);
  cmd = batteryTypeMap[sv] || null;
  refresh = ["QPIRI", "QMOD", "QPIGS"];

} else if (param === "max_discharging_current") {
  const sv = cleanString(v);
  if (sv === "0") return null;

  const nv = toNum(sv);
  if (nv == null) return null;

  cmd = `PBATMAXDISC${pad3(clamp(nv, 1, 200))}`;
  refresh = ["QPIRI", "QPIGS"];

} else if (param === "battery_recharge_capacity_pct") {
  const nv = toNum(v); if (nv == null) return null;
  cmd = `PBCC${pad3(clamp(nv, 5, 95))}`;
  refresh = ["QDOP", "QPIGS"];

} else if (param === "battery_redischarge_capacity_pct") {
  const nv = toNum(v); if (nv == null) return null;
  cmd = `PBDC${pad3(clamp(nv, 10, 100))}`;
  refresh = ["QDOP", "QPIGS"];

} else if (param === "battery_under_capacity_pct") {
  const nv = toNum(v); if (nv == null) return null;
  cmd = `PSDC${pad3(clamp(nv, 0, 90))}`;
  refresh = ["QDOP", "QPIGS"];
}

if (!cmd) return null;

// -------------------------------------------------
// Construction sortie directe
// -------------------------------------------------
const setMsg = mk(cmd, {
  _burst: false,
  _origin: "ha_set",
  _ha_param: param,
  _ha_value: v
});

const refreshMsgs = refresh.map(c => mk(c, {
  _origin: "ha_refresh",
  _from_param: param
}));

const out = [setMsg, ...refreshMsgs];

node.status({
  fill: "green",
  shape: "dot",
  text: `SET ${param} (${cmd}) + refresh x${refreshMsgs.length}`
});

return [null, out];

// ====== CONSTRUIRE COMMANDE (Voltronic) ======
const helpers = global.get("helpers");

if (!helpers || typeof helpers.buildVoltronicCommand !== "function") {
  node.error("helpers.buildVoltronicCommand introuvable (global.helpers)");
  return null;
}

const inv = msg.inverterNum ?? 1;
const isRawManual = (msg._raw_manual === true);

function cleanCmd(v) {
  let s = String(v ?? "").trim();
  if (!s) return "";

  // tente de décoder un string JSON du genre "\"QPIGS\""
  try {
    if (
      (s.startsWith('"') && s.endsWith('"')) ||
      (s.startsWith('\\"') || s.endsWith('\\"'))
    ) {
      const parsed = JSON.parse(s);
      if (typeof parsed === "string") s = parsed;
    }
  } catch (e) {
    // ignore
  }

  // retire guillemets parasites début / fin
  s = s.trim().replace(/^"+|"+$/g, "");

  return s.trim();
}

// priorité à msg.command
let rawCmd = cleanCmd(msg.command ?? msg._cmd ?? msg.payload ?? "");
if (!rawCmd) return null;

// En mode normal on standardise en uppercase
// En raw manuel on conserve tel quel puis on nettoie l'espace seulement
let cmd = isRawManual ? rawCmd : rawCmd.toUpperCase();

// filtre léger : caractères autorisés pour éviter les entrées sales
// on reste souple pour ne pas bloquer des commandes valides selon modèles
if (!/^[A-Za-z0-9.\-]+$/.test(cmd)) {
  node.warn(`Commande rejetée (caractères invalides): ${cmd}`);
  return null;
}

// met à jour le message
msg.inverterNum = inv;
msg.command = cmd;
msg._cmd = cmd;
msg._raw_command = rawCmd;
msg._raw_manual = isRawManual;

// construit la trame
let buf;
try {
  buf = helpers.buildVoltronicCommand(cmd);
} catch (e) {
  node.error(`Erreur buildVoltronicCommand("${cmd}") : ${e.message || e}`, msg);
  return null;
}

const ts = Date.now();

// payload série/tcp
msg.payload = buf;

// debug TX
msg._tx_ts = ts;
msg._tx_ascii = cmd;
msg._tx_hex = buf.toString("hex");
msg._raw_command_buffer_hex = msg._tx_hex;

// status
node.status({
  fill: isRawManual ? "yellow" : "blue",
  shape: "dot",
  text: `${cmd}${isRawManual ? " manual" : ""} -> ond${inv}`
});

// mémorise en un seul objet
flow.set(`inv${inv}_last_tx`, {
  cmd,
  raw_command: rawCmd,
  raw_manual: isRawManual,
  ts,
  tx_hex: msg._tx_hex
});

return msg;

// ====== REQUETES ======
// Boot burst + polling léger + QPIGS2 auto-disable/retry + diag + énergies filtrées par support
// - numéro d'onduleur en dur
// - 1 flow = 1 onduleur
// - QPIGS2 alterné en temps réel
// - si QPIGS2 est désactivé: QPIGS seul + 1 probe/heure
// - commandes énergie désactivées individuellement après apprentissage parser
// - compatible avec queue/pump/parser refaits

const inverterNum = 3;
const ts = Date.now();
const now = new Date();

const pad2 = (n) => String(n).padStart(2, "0");
const yyyy = now.getFullYear();
const mm = pad2(now.getMonth() + 1);
const dd = pad2(now.getDate());

const yyyymm = `${yyyy}${mm}`;
const yyyymmdd = `${yyyy}${mm}${dd}`;

// -------------------------------------------------
// Helpers
// -------------------------------------------------
function makeCmd(cmd, extra = {}) {
  return {
    inverterNum,
    command: cmd,
    _cmd: cmd,
    payload: cmd,
    _origin: extra._origin || "poll",
    ...extra
  };
}

function baseCmdName(cmd) {
  const s = String(cmd || "").toUpperCase().trim();

  if (s.startsWith("QEY")) return "QEY";
  if (s.startsWith("QEM")) return "QEM";
  if (s.startsWith("QED")) return "QED";
  if (s.startsWith("QLY")) return "QLY";
  if (s.startsWith("QLM")) return "QLM";
  if (s.startsWith("QLD")) return "QLD";

  return s;
}

function getCmdState(cmd) {
  const base = baseCmdName(cmd);
  const key = `inv${inverterNum}_cmd_state_${base}`;
  let st = flow.get(key);

  if (!st || typeof st !== "object") {
    st = {
      nak_count: 0,
      disabled: false,
      last_try: 0,
      last_ok: 0,
      last_nak: 0,
      retry_after: 0,
      reason: ""
    };
    flow.set(key, st);
  }

  return st;
}

function setCmdState(cmd, st) {
  const base = baseCmdName(cmd);
  flow.set(`inv${inverterNum}_cmd_state_${base}`, st);
}

function shouldScheduleLearnedCmd(cmd) {
  const st = getCmdState(cmd);

  if (st.disabled !== true) return true;

  const retryAfter = Number(st.retry_after || 0);
  return ts >= retryAfter;
}

function markCmdScheduled(cmd, reason = "") {
  const st = getCmdState(cmd);
  st.last_try = ts;
  if (reason) st.reason = reason;
  setCmdState(cmd, st);
}

function pushLearnedCmd(cmd, extra = {}) {
  if (!shouldScheduleLearnedCmd(cmd)) return false;

  msgs.push(makeCmd(cmd, extra));
  markCmdScheduled(cmd, extra._origin || "poll");
  return true;
}

function getQpigs2State() {
  const key = `inv${inverterNum}_qpigs2_state`;
  let st = flow.get(key);

  if (!st || typeof st !== "object") {
    st = {
      fail_count: 0,
      disabled: false,
      last_try: 0,
      last_ok: 0,
      last_fail: 0,
      reason: ""
    };
    flow.set(key, st);
  }

  return st;
}

function setQpigs2State(st) {
  flow.set(`inv${inverterNum}_qpigs2_state`, st);
}

// -------------------------------------------------
// Etat local
// -------------------------------------------------
let alt = context.get("alt");
if (alt == null) alt = 0;

let firstRun = context.get("firstRun");
if (firstRun === undefined) firstRun = true;

if (msg && msg.forceFirstRun === true) {
  firstRun = true;
}

// timers
let nextQMOD = context.get("nextQMOD");
let nextHour = context.get("nextHour");
let nextDay10m = context.get("nextDay10m");
let nextMonth6 = context.get("nextMonth6");
let nextYear24 = context.get("nextYear24");
let nextQPIRI = context.get("nextQPIRI");
let nextQDOP = context.get("nextQDOP");
let nextQPIWS = context.get("nextQPIWS");

// -------------------------------------------------
// Etat QPIGS2
// -------------------------------------------------
let qpigs2 = getQpigs2State();
const RETRY_MS = 60 * 60 * 1000; // 1h

function shouldTryQpigs2Now() {
  if (!qpigs2.disabled) return true;
  return (ts - Number(qpigs2.last_try || 0)) >= RETRY_MS;
}

function markQpigs2Scheduled(reason) {
  qpigs2.last_try = ts;
  qpigs2.reason = reason || qpigs2.reason || "";
  setQpigs2State(qpigs2);
}

// -------------------------------------------------
// Liste de commandes à envoyer
// -------------------------------------------------
const msgs = [];

// -------------------------------------------------
// Tick temps réel
// -------------------------------------------------
function pushRealtimeTick() {
  if (!qpigs2.disabled) {
    if (alt === 0) {
      msgs.push(makeCmd("QPIGS", {
        _origin: "poll_realtime"
      }));
      alt = 1;
    } else {
      msgs.push(makeCmd("QPIGS2", {
        _origin: "poll_realtime",
        _qpigs2_probe: false
      }));
      markQpigs2Scheduled("normal");
      alt = 0;
    }
    return;
  }

  msgs.push(makeCmd("QPIGS", {
    _origin: "poll_realtime"
  }));

  if (shouldTryQpigs2Now()) {
    msgs.push(makeCmd("QPIGS2", {
      _origin: "poll_realtime_retry",
      _qpigs2_probe: true
    }));
    markQpigs2Scheduled("hourly_retry");
  }
}

// -------------------------------------------------
// Helpers énergie
// -------------------------------------------------
function pushEnergyBootBurst() {
  pushLearnedCmd("QET", { _origin: "poll_boot_energy" });
  pushLearnedCmd(`QEY${yyyy}`, { _origin: "poll_boot_energy" });
  pushLearnedCmd(`QEM${yyyymm}`, { _origin: "poll_boot_energy" });
  pushLearnedCmd(`QED${yyyymmdd}`, { _origin: "poll_boot_energy" });

  pushLearnedCmd("QLT", { _origin: "poll_boot_energy" });
  pushLearnedCmd(`QLY${yyyy}`, { _origin: "poll_boot_energy" });
  pushLearnedCmd(`QLM${yyyymm}`, { _origin: "poll_boot_energy" });
  pushLearnedCmd(`QLD${yyyymmdd}`, { _origin: "poll_boot_energy" });
}

function pushEnergyHourly() {
  pushLearnedCmd("QET", { _origin: "poll_energy" });
  pushLearnedCmd("QLT", { _origin: "poll_energy" });
}

function pushEnergyDaily() {
  pushLearnedCmd(`QED${yyyymmdd}`, { _origin: "poll_energy" });
  pushLearnedCmd(`QLD${yyyymmdd}`, { _origin: "poll_energy" });
}

function pushEnergyMonthly() {
  pushLearnedCmd(`QEM${yyyymm}`, { _origin: "poll_energy" });
  pushLearnedCmd(`QLM${yyyymm}`, { _origin: "poll_energy" });
}

function pushEnergyYearly() {
  pushLearnedCmd(`QEY${yyyy}`, { _origin: "poll_energy" });
  pushLearnedCmd(`QLY${yyyy}`, { _origin: "poll_energy" });
}

// =================================================
// 1) FIRST RUN / BOOT BURST
// =================================================
if (firstRun) {
  const burst = [
    "QPIRI",
    "QDOP",
    "QMOD",
    "QMN",
    "QID",
    "QVFW",
    "QVFW3",
    "QPIWS"
  ];

  burst.forEach((c) => {
    msgs.push(makeCmd(c, {
      _origin: "poll_boot"
    }));
  });

  // énergies boot, mais seulement si supportées ou retestables
  pushEnergyBootBurst();

  // realtime initial
  msgs.push(makeCmd("QPIGS", {
    _origin: "poll_boot"
  }));

  msgs.push(makeCmd("QPIGS2", {
    _origin: "poll_boot",
    _qpigs2_probe: qpigs2.disabled === true
  }));
  markQpigs2Scheduled("boot");

  // initialise les timers
  nextQMOD = ts + 5 * 60 * 1000;
  nextHour = ts + 60 * 60 * 1000;
  nextDay10m = ts + 10 * 60 * 1000;
  nextMonth6 = ts + 6 * 60 * 60 * 1000;
  nextYear24 = ts + 24 * 60 * 60 * 1000;
  nextQPIRI = ts + 5 * 60 * 1000;
  nextQDOP = ts + 5 * 60 * 1000;
  nextQPIWS = ts + 5 * 60 * 1000;

  firstRun = false;

  node.status({
    fill: "green",
    shape: "dot",
    text: `FIRST RUN: ${msgs.length} cmds`
  });
}

// =================================================
// 2) MODE NORMAL
// =================================================
else {
  // QMOD toutes les 5 min
  if (nextQMOD == null) nextQMOD = ts + 5 * 60 * 1000;
  if (ts >= nextQMOD) {
    msgs.push(makeCmd("QMOD", {
      _origin: "poll_slow"
    }));
    nextQMOD = ts + 5 * 60 * 1000;
  }

  // QPIRI toutes les 5 min
  if (nextQPIRI == null) nextQPIRI = ts + 5 * 60 * 1000;
  if (ts >= nextQPIRI) {
    msgs.push(makeCmd("QPIRI", {
      _origin: "poll_slow"
    }));
    nextQPIRI = ts + 5 * 60 * 1000;
  }

  // QDOP toutes les 5 min
  if (nextQDOP == null) nextQDOP = ts + 5 * 60 * 1000;
  if (ts >= nextQDOP) {
    msgs.push(makeCmd("QDOP", {
      _origin: "poll_slow"
    }));
    nextQDOP = ts + 5 * 60 * 1000;
  }

  // QPIWS toutes les 5 min
  if (nextQPIWS == null) nextQPIWS = ts + 5 * 60 * 1000;
  if (ts >= nextQPIWS) {
    msgs.push(makeCmd("QPIWS", {
      _origin: "poll_slow"
    }));
    nextQPIWS = ts + 5 * 60 * 1000;
  }

  // toutes les heures
  if (nextHour == null) nextHour = ts + 60 * 60 * 1000;
  if (ts >= nextHour) {
    pushEnergyHourly();

    msgs.push(makeCmd("QMN", { _origin: "poll_diag" }));
    msgs.push(makeCmd("QID", { _origin: "poll_diag" }));
    msgs.push(makeCmd("QVFW", { _origin: "poll_diag" }));
    msgs.push(makeCmd("QVFW3", { _origin: "poll_diag" }));

    nextHour = ts + 60 * 60 * 1000;
  }

  // journalier toutes les 10 min
  if (nextDay10m == null) nextDay10m = ts + 10 * 60 * 1000;
  if (ts >= nextDay10m) {
    pushEnergyDaily();
    nextDay10m = ts + 10 * 60 * 1000;
  }

  // mensuel toutes les 6h
  if (nextMonth6 == null) nextMonth6 = ts + 6 * 60 * 60 * 1000;
  if (ts >= nextMonth6) {
    pushEnergyMonthly();
    nextMonth6 = ts + 6 * 60 * 60 * 1000;
  }

  // annuel toutes les 24h
  if (nextYear24 == null) nextYear24 = ts + 24 * 60 * 60 * 1000;
  if (ts >= nextYear24) {
    pushEnergyYearly();
    nextYear24 = ts + 24 * 60 * 60 * 1000;
  }

  // temps réel en dernier
  pushRealtimeTick();

  node.status({
    fill: qpigs2.disabled ? "yellow" : "green",
    shape: "dot",
    text: qpigs2.disabled
      ? `QPIGS2 disabled (${qpigs2.fail_count}/3), retry 1h`
      : `QPIGS2 enabled (${msgs.length} cmds)`
  });
}

// -------------------------------------------------
// Sauvegarde contexte
// -------------------------------------------------
context.set("alt", alt);
context.set("firstRun", firstRun);
context.set("nextQMOD", nextQMOD);
context.set("nextHour", nextHour);
context.set("nextDay10m", nextDay10m);
context.set("nextMonth6", nextMonth6);
context.set("nextYear24", nextYear24);
context.set("nextQPIRI", nextQPIRI);
context.set("nextQDOP", nextQDOP);
context.set("nextQPIWS", nextQPIWS);

return [msgs];

// ====== PARSER 1 (Voltronic) - QUEUE MODE + RAW CMD/RESP + LEARNING ======
// Entrée: msg.payload = Buffer
// Sorties:
//   1) trigger pump (msg.topic="pump")
//   2) data parsée (vers normalize state)

const inv = msg.inverterNum ?? 1;
if (!Buffer.isBuffer(msg.payload)) return null;

const CR = 0x0D;
const NAK = 0x15;

const inflightKey = `inv${inv}_inflight`;

// -------------------------------------------------
// RX buffer
// -------------------------------------------------
let rx = context.get("rxbuf");
if (!Buffer.isBuffer(rx)) rx = Buffer.alloc(0);

// sécurité overflow
if (rx.length > 8192) rx = Buffer.alloc(0);

// concat
rx = Buffer.concat([rx, msg.payload]);

// -------------------------------------------------
// Helpers support commandes apprises
// -------------------------------------------------
const LEARNED_CMDS = new Set([
  "QPIGS2",
  "QET", "QEY", "QEM", "QED",
  "QLT", "QLY", "QLM", "QLD"
]);

function baseCmdName(cmd) {
  const s = String(cmd || "").toUpperCase().trim();

  if (s.startsWith("QEY")) return "QEY";
  if (s.startsWith("QEM")) return "QEM";
  if (s.startsWith("QED")) return "QED";
  if (s.startsWith("QLY")) return "QLY";
  if (s.startsWith("QLM")) return "QLM";
  if (s.startsWith("QLD")) return "QLD";

  return s;
}

function getCmdState(inv, cmd) {
  const base = baseCmdName(cmd);
  const key = `inv${inv}_cmd_state_${base}`;
  let st = flow.get(key);

  if (!st || typeof st !== "object") {
    st = {
      nak_count: 0,
      disabled: false,
      last_try: 0,
      last_ok: 0,
      last_nak: 0,
      retry_after: 0,
      reason: ""
    };
    flow.set(key, st);
  }

  return st;
}

function setCmdState(inv, cmd, st) {
  const base = baseCmdName(cmd);
  flow.set(`inv${inv}_cmd_state_${base}`, st);
}

function markCmdSuccess(inv, cmd) {
  const base = baseCmdName(cmd);
  if (!LEARNED_CMDS.has(base)) return;

  const st = getCmdState(inv, base);
  st.nak_count = 0;
  st.disabled = false;
  st.last_ok = Date.now();
  st.retry_after = 0;
  st.reason = "";
  setCmdState(inv, base, st);

  if (base === "QPIGS2") {
    // compat éventuelle
    flow.set(`inv${inv}_supports_qpigs2`, true);

    // synchronise aussi l'ancien état qpigs2 si utilisé ailleurs
    let qp = flow.get(`inv${inv}_qpigs2_state`);
    if (!qp || typeof qp !== "object") qp = {};
    qp.fail_count = 0;
    qp.disabled = false;
    qp.last_ok = Date.now();
    qp.reason = "";
    flow.set(`inv${inv}_qpigs2_state`, qp);
  }
}

function markCmdNak(inv, cmd) {
  const base = baseCmdName(cmd);
  if (!LEARNED_CMDS.has(base)) return;

  const st = getCmdState(inv, base);
  st.nak_count = Number(st.nak_count || 0) + 1;
  st.last_nak = Date.now();
  st.reason = "nak";

  if (st.nak_count >= 2) {
    st.disabled = true;
    st.retry_after = Date.now() + (60 * 60 * 1000); // 1h
  }

  setCmdState(inv, base, st);

  if (base === "QPIGS2") {
    if (st.disabled) {
      flow.set(`inv${inv}_supports_qpigs2`, false);
    }

    // synchronise aussi l'ancien état qpigs2 si utilisé ailleurs
    let qp = flow.get(`inv${inv}_qpigs2_state`);
    if (!qp || typeof qp !== "object") qp = {};
    qp.fail_count = Number(st.nak_count || 0);
    qp.last_fail = Date.now();
    qp.reason = "nak";
    qp.disabled = !!st.disabled;
    flow.set(`inv${inv}_qpigs2_state`, qp);
  }
}

// -------------------------------------------------
// Extraction frames
// - supporte:
//   * frames ASCII + CRC + CR
//   * NAK brut 0x15 sans CR
// -------------------------------------------------
const frames = [];

while (rx.length > 0) {
  // cas 1: premier octet = NAK brut
  if (rx[0] === NAK) {
    frames.push(Buffer.from([NAK]));
    rx = rx.slice(1);
    continue;
  }

  // cas 2: frame terminée par CR
  const idx = rx.indexOf(CR);
  if (idx === -1) break;

  frames.push(rx.slice(0, idx + 1));
  rx = rx.slice(idx + 1);
}

context.set("rxbuf", rx);

if (!frames.length) return null;

// -------------------------------------------------
// Inflight courant
// -------------------------------------------------
const inflight = flow.get(inflightKey);

const inflightCmd =
  inflight?.cmd ||
  "UNKNOWN";

const inflightRawCmd =
  inflight?.raw ||
  inflight?.raw_command ||
  inflightCmd;

const inflightRawManual =
  inflight?.raw_manual === true;

// -------------------------------------------------
// Nettoyage frame -> ascii
// -------------------------------------------------
function cleanAsciiFromFrame(frameBuf) {
  if (!Buffer.isBuffer(frameBuf) || frameBuf.length === 0) return "";

  // NAK brut
  if (frameBuf.length === 1 && frameBuf[0] === NAK) return "NAK";

  // Normalement: <data ASCII> + <CRC 2 bytes> + <CR>
  if (frameBuf.length >= 3 && frameBuf[frameBuf.length - 1] === CR) {
    return frameBuf.slice(0, -3).toString("ascii");
  }

  // fallback: retire juste CR si présent
  if (frameBuf[frameBuf.length - 1] === CR) {
    return frameBuf.slice(0, -1).toString("ascii");
  }

  return frameBuf.toString("ascii");
}

function parseFrame(frameBuf, cmd, rawCmd) {
  const ascii = cleanAsciiFromFrame(frameBuf);
  const rawResponse = String(ascii || "").trim();
  const rawHex = frameBuf.toString("hex");

// NAK
if (
  ascii === "NAK" ||
  rawResponse === "NAK" ||
  rawResponse.includes("NAK") ||
  ascii.includes("NAK")
) {
  return {
    inverter: inv,
    command: cmd,
    raw_command: rawCmd,
    raw_response: "NAK",
    raw_frame_hex: rawHex,
    nak: true,
    raw: "NAK",
    fields: [],
    nums: [],
    value: null
  };
}

  // body sans parenthèses
  let body = rawResponse;
  if (body.startsWith("(")) body = body.slice(1);
  if (body.endsWith(")")) body = body.slice(0, -1);
  body = body.trim();

  const fields = body ? body.split(/\s+/) : [];
  const nums = fields.map(v => {
    const n = Number(v);
    return Number.isFinite(n) ? n : null;
  });

  const base = baseCmdName(cmd);
  const isEnergyCmd = ["QET", "QEY", "QEM", "QED", "QLT", "QLY", "QLM", "QLD"].includes(base);

  let value = null;
  if (isEnergyCmd && fields.length >= 1) {
    const n0 = Number(fields[0]);
    if (Number.isFinite(n0)) value = n0;
  }

  return {
    inverter: inv,
    command: cmd,
    raw_command: rawCmd,
    raw_response: rawResponse,
    raw_frame_hex: rawHex,
    nak: false,
    raw: body,
    fields,
    nums,
    value
  };
}

// -------------------------------------------------
// Queue mode:
// - 1ère frame => inflight
// - suivantes => UNKNOWN
// -------------------------------------------------
const outMsgs = [];
const now = Date.now();

for (let i = 0; i < frames.length; i++) {
  const cmd = (i === 0) ? inflightCmd : "UNKNOWN";
  const rawCmd = (i === 0) ? inflightRawCmd : "UNKNOWN";
  const isRawManual = (i === 0) ? inflightRawManual : false;

  const parsed = parseFrame(frames[i], cmd, rawCmd);

  if (i === 0 && cmd !== "UNKNOWN") {
    if (parsed.nak === true) {
      markCmdNak(inv, cmd);
    } else {
      markCmdSuccess(inv, cmd);
    }
  }

  outMsgs.push({
    inverterNum: inv,
    _cmd: cmd,
    command: cmd,
    _raw_command: rawCmd,
    _raw_response: parsed.raw_response,
    _raw_frame_hex: parsed.raw_frame_hex,
    _raw_manual: isRawManual,
    payload: parsed,
    _rx_ts: now
  });
}

// -------------------------------------------------
// Libère inflight dès qu'au moins une frame est reçue
// -------------------------------------------------
flow.set(inflightKey, null);

// -------------------------------------------------
// Trigger pump immédiat
// -------------------------------------------------
const pumpMsg = { inverterNum: inv, topic: "pump" };

return [[pumpMsg], outMsgs];

// ====== NORMALIZE STATE (AUTO / MULTI-MODEL) - FILTERED + RAW CMD/RESP + TZ dynamic + GRID TODAY ======
if (!msg.payload || typeof msg.payload !== "object") return null;

const inv = msg.inverterNum ?? msg.payload.inverter ?? 1;

// Normaliser la commande
const cmd = String(msg.payload.command || msg.command || msg._cmd || "UNKNOWN")
  .trim()
  .toUpperCase();

const f = Array.isArray(msg.payload.fields) ? msg.payload.fields : [];
const n = Array.isArray(msg.payload.nums) ? msg.payload.nums : [];
const value = msg.payload.value;

let state = context.get("state");
if (!state || typeof state !== "object") state = {};

// -------------------------
// Helpers de base
// -------------------------
const num = (idx) => (Number.isFinite(n[idx]) ? n[idx] : null);
const int = (idx) => {
  const v = num(idx);
  return v == null ? null : Math.trunc(v);
};
const round = (v, d) => {
  const nn = Number(v);
  if (!Number.isFinite(nn)) return null;
  const m = 10 ** d;
  return Math.round(nn * m) / m;
};
const finiteNumber = (x) => {
  const nn = Number(x);
  return Number.isFinite(nn) ? nn : null;
};

// -------------------------
// Helpers filtres
// -------------------------
const MAX_W = 15000;
const MAX_A = 350;

function sanitizeWithLastValid(key, value, opts = {}) {
  const {
    min = null,
    max = null,
    forceInt = false
  } = opts;

  const v = finiteNumber(value);
  if (v == null) return;

  const lastKey = `inv${inv}_last_ok_${key}`;
  const lastOk = flow.get(lastKey);

  let ok = true;
  if (min != null && v < min) ok = false;
  if (max != null && v > max) ok = false;

  if (!ok) {
    if (lastOk != null && Number.isFinite(lastOk)) {
      state[key] = lastOk;
    } else {
      state[key] = null;
    }
    state._spike = state._spike || [];
    state._spike.push({ key, raw: v, min, max });
    return;
  }

  state[key] = forceInt ? Math.trunc(v) : v;
  flow.set(lastKey, state[key]);
}

function sanitizeW(key, { allowNegative = true, forceNonNegative = false, forceInt = true } = {}) {
  let v = finiteNumber(state[key]);
  if (v == null) return;

  if (forceNonNegative && v < 0) v = 0;

  const min = allowNegative ? -MAX_W : 0;
  const max = MAX_W;
  sanitizeWithLastValid(key, v, { min, max, forceInt });
}

function sanitizeA(key, { allowNegative = false, forceNonNegative = true, decimals = 1 } = {}) {
  let v = finiteNumber(state[key]);
  if (v == null) return;

  if (forceNonNegative && v < 0) v = 0;
  if (Number.isFinite(decimals)) v = round(v, decimals);

  const min = allowNegative ? -MAX_A : 0;
  const max = MAX_A;
  sanitizeWithLastValid(key, v, { min, max, forceInt: false });
}

function sanitizePct(key) {
  const v = finiteNumber(state[key]);
  if (v == null) return;
  sanitizeWithLastValid(key, v, { min: 0, max: 100, forceInt: true });
}

// --- apprentissage index pv1_power par node (donc par inverter) ---
let pv1PowerIdx = context.get("pv1PowerIdx");

// ===== RAW RESPONSE (MANUAL TEST ONLY) =====
state.diag = state.diag || {};

if (state.diag.raw_command !== undefined) delete state.diag.raw_command;
if (state.diag.raw_response_hex !== undefined) delete state.diag.raw_response_hex;
if (state.diag._last_raw_command_ts !== undefined) delete state.diag._last_raw_command_ts;
if (state.diag._last_raw_response_hex_ts !== undefined) delete state.diag._last_raw_response_hex_ts;

if (msg._raw_manual === true) {
  const rawResp =
    msg._raw_response ??
    msg.raw_response ??
    msg.payload?.raw_response ??
    msg.payload?.raw ??
    null;

  if (rawResp !== null && rawResp !== undefined) {
    state.diag.raw_response = String(rawResp).trim() || "";
    state.diag._last_raw_response_ts = Date.now();
  }
}

// ===== QPIGS =====
if (cmd === "QPIGS" && f.length >= 16) {
  if (f.length > 0) state.grid_voltage = round(num(0), 1);
  if (f.length > 1) state.grid_frequency = round(num(1), 1);
  if (f.length > 2) state.ac_output_voltage = round(num(2), 1);
  if (f.length > 3) state.ac_output_frequency = round(num(3), 1);

  if (f.length > 4) state.ac_output_apparent_power = int(4);
  if (f.length > 5) state.ac_output_active_power = int(5);
  if (f.length > 6) state.output_load_percent = int(6);

  if (f.length > 7) state.bus_voltage = int(7);

  if (f.length > 8) state.battery_voltage = round(num(8), 2);
  if (f.length > 9) state.battery_charging_current = round(num(9), 1);
  if (f.length > 10) state.battery_capacity = int(10);
  if (f.length > 11) state.inverter_heat_sink_temp = int(11);

  if (f.length > 12) state.pv1_input_current = round(num(12), 1);
  if (f.length > 13) state.pv1_input_voltage = round(num(13), 1);

  if (f.length > 14) state.battery_voltage_from_scc = round(num(14), 2);
  if (f.length > 15) state.battery_discharge_current = round(num(15), 1);

  const IchgA = Number.isFinite(state.battery_charging_current) ? state.battery_charging_current : 0;
  const IdisA = Number.isFinite(state.battery_discharge_current) ? state.battery_discharge_current : 0;
  state.global_current = round(IchgA - IdisA, 1);

  const Vac = Number.isFinite(state.ac_output_voltage) ? state.ac_output_voltage : null;
  const Pac = Number.isFinite(state.ac_output_active_power) ? state.ac_output_active_power : null;
  if (Vac != null && Vac > 1 && Pac != null) {
    state.inverter_output_current = Math.round((Pac / Vac) * 10) / 10;
  } else {
    state.inverter_output_current = null;
  }

  if (pv1PowerIdx != null && f.length > pv1PowerIdx) {
    state.pv1_power = int(pv1PowerIdx);
  } else {
    const candidates = [19, 20, 18, 17, 16];
    for (const idx of candidates) {
      if (f.length > idx && Number.isFinite(n[idx])) {
        const I = state.pv1_input_current;
        const V = state.pv1_input_voltage;
        const pCalc = (Number.isFinite(I) && Number.isFinite(V)) ? (I * V) : null;
        const pField = n[idx];

        if (pCalc != null && pCalc > 10) {
          const ratio = pField / pCalc;
          if (ratio > 0.8 && ratio < 1.2) {
            pv1PowerIdx = idx;
            context.set("pv1PowerIdx", pv1PowerIdx);
            state.pv1_power = int(idx);
            break;
          }
        } else {
          if (idx === 19) {
            state.pv1_power = int(19);
            break;
          }
        }
      }
    }
  }

  if (f.length > 24 && Number.isFinite(n[24])) {
    state.grid_power = int(24);
  }

  state._last_qpigs_ts = Date.now();
}

// ===== QPIGS2 =====
if (cmd === "QPIGS2" && f.length >= 3) {
  state.pv2_input_current = round(num(0), 1);
  state.pv2_input_voltage = round(num(1), 1);
  state.pv2_power = int(2);
  state._last_qpigs2_ts = Date.now();
}

// ===== QMOD =====
if (cmd === "QMOD") {
  const rawMode = (f[0] ?? msg.payload.raw ?? "").toString().trim();
  const modeMap = { P: "Power On", S: "Standby", L: "Grid", B: "Battery", F: "Fault" };
  state.operation_mode = modeMap[rawMode] || rawMode || null;
  state.operation_mode_code = rawMode || null;
  state._last_qmod_ts = Date.now();
}

// ===== QPIRI =====
if (cmd === "QPIRI" && msg.payload?.nak !== true) {
  const nf = (idx) => {
    const v = (f && f.length > idx) ? f[idx] : null;
    const nn = Number(v);
    return Number.isFinite(nn) ? nn : null;
  };

  const mapBatteryType = (code) => {
    const m = { 0: "AGM", 1: "Flooded", 2: "User", 3: "Pylon", 5: "Weco", 6: "Soltaro", 8: "Lib", 9: "Lic" };
    return m[code] ?? String(code ?? "");
  };
  const mapOutputPriority = (code) => {
    const m = { 0: "UtilitySolarBat", 1: "SolarUtilityBat", 2: "SolarBatUtility" };
    return m[code] ?? String(code ?? "");
  };
  const mapChargerPriority = (code) => {
    const m = { 1: "Solar first", 2: "Solar + Utility", 3: "Only solar" };
    return m[code] ?? String(code ?? "");
  };

  if (!state.params || typeof state.params !== "object") state.params = {};

  const battTypeCode = nf(12);
  const outPrioCode = nf(16);
  const chgPrioCode = nf(17);

  state.params.qpiri = {
    battery_recharge_voltage: nf(8),
    battery_under_voltage: nf(9),
    battery_bulk_voltage: nf(10),
    battery_float_voltage: nf(11),

    battery_type_code: battTypeCode,
    battery_type: mapBatteryType(battTypeCode),

    max_ac_charging_current: nf(13),
    max_charging_current: nf(14),

    output_source_priority_code: outPrioCode,
    output_source_priority: mapOutputPriority(outPrioCode),

    charger_source_priority_code: chgPrioCode,
    charger_source_priority: mapChargerPriority(chgPrioCode),

    battery_re_discharge_voltage: nf(22),
    max_discharging_current: nf(27),

    ts: Date.now()
  };

  state._last_qpiri_ts = Date.now();
}

// ===== QDOP =====
if (cmd === "QDOP" && msg.payload?.nak !== true) {
  const nf = (idx) => {
    const v = (f && f.length > idx) ? f[idx] : null;
    const nn = Number(v);
    return Number.isFinite(nn) ? nn : null;
  };

  if (!state.params || typeof state.params !== "object") state.params = {};

  state.params.qdop = {
    battery_recharge_capacity_pct: nf(8),
    battery_redischarge_capacity_pct: nf(9),
    battery_under_capacity_pct: nf(10),
    ts: Date.now()
  };

  state._last_qdop_ts = Date.now();
}

// ===== DIAGNOSTIC (model/serial/fw + faults/warnings) =====
if (cmd === "QMN" && msg.payload?.nak !== true) {
  state.diag.model = (f[0] ?? msg.payload.raw ?? "").toString().trim() || null;
  state._last_qmn_ts = Date.now();
}

if ((cmd === "QID" || cmd === "QSID") && msg.payload?.nak !== true) {
  state.diag.serial = (f[0] ?? msg.payload.raw ?? "").toString().trim() || null;
  state._last_qid_ts = Date.now();
}

if ((cmd === "QVFW" || cmd === "QVFW3") && msg.payload?.nak !== true) {
  const fw = (f[0] ?? msg.payload.raw ?? "").toString().trim() || null;
  if (cmd === "QVFW") state.diag.fw_main = fw;
  if (cmd === "QVFW3") state.diag.fw_remote = fw;
  state._last_qvfw_ts = Date.now();
}

// ===== QPIWS =====
if (cmd === "QPIWS" && msg.payload?.nak !== true) {
  const bits = String(f[0] ?? msg.payload.raw ?? "").trim();

  const bit = (i) => (bits.length > i ? bits.charAt(i) === "1" : false);
  const a1_fault = bit(1);

  const map = [
    { i: 0, label: "PV loss", kind: "warn" },
    { i: 1, label: "Inverter fault", kind: "fault" },
    { i: 2, label: "Bus over", kind: "fault" },
    { i: 3, label: "Bus under", kind: "fault" },
    { i: 4, label: "Bus soft fail", kind: "fault" },
    { i: 5, label: "Line fail", kind: "warn" },
    { i: 6, label: "OPV short", kind: "fault" },
    { i: 7, label: "Inverter voltage low", kind: "fault" },
    { i: 8, label: "Inverter voltage high", kind: "fault" },
    { i: 9, label: "Over temperature", kind: () => a1_fault ? "fault" : "warn" },
    { i: 10, label: "Fan locked", kind: () => a1_fault ? "fault" : "warn" },
    { i: 11, label: "Battery voltage high", kind: () => a1_fault ? "fault" : "warn" },
    { i: 12, label: "Battery low alarm", kind: "warn" },
    { i: 14, label: "Battery shutdown", kind: "warn" },
    { i: 15, label: "Battery derating", kind: "warn" },
    { i: 16, label: "Over load", kind: () => a1_fault ? "fault" : "warn" },
    { i: 17, label: "EEPROM fault", kind: "warn" },
    { i: 18, label: "Inverter over current", kind: "fault" },
    { i: 19, label: "Inverter soft fail", kind: "fault" },
    { i: 20, label: "Self test fail", kind: "fault" },
    { i: 21, label: "OP DC voltage over", kind: "fault" },
    { i: 23, label: "Current sensor fail", kind: "fault" },
    { i: 33, label: "Low PV energy", kind: "warn" },
    { i: 34, label: "High AC input", kind: "warn" },
    { i: 35, label: "Battery equalization", kind: "warn" }
  ];

  const faults = [];
  const warns = [];

  for (const m of map) {
    if (!bit(m.i)) continue;
    const k = (typeof m.kind === "function") ? m.kind() : m.kind;
    if (k === "fault") faults.push(m.label);
    else warns.push(m.label);
  }

  state.diag.fault_state = faults.length ? "FAULT" : "OK";
  state.diag.fault_details = faults.length ? faults.join(", ") : "None";
  state.diag.warn_state = warns.length ? "WARN" : "OK";
  state.diag.warn_details = warns.length ? warns.join(", ") : "None";
  state.diag.has_fault = faults.length > 0;
  state.diag.has_warning = warns.length > 0;
  state.diag._last_qpiws_ts = Date.now();
}

// ===== Support QPIGS2 =====
const supportsKey = `inv${inv}_supports_qpigs2`;
const supports = flow.get(supportsKey);
if (supports !== undefined) state.supports_qpigs2 = (supports !== false);

// ===== ENERGIES =====
const round2 = (v) => (v == null ? null : Math.round(v * 100) / 100);
const toKwhToday = (v) => (!Number.isFinite(v) ? null : round2(v / 1000));
const toKwhAuto = (v) => (!Number.isFinite(v) ? null : (v >= 10000 ? round2(v / 1000) : round2(v)));

if (Number.isFinite(value)) {
  if (cmd === "QET") { state.pv_energy_total_raw = value; state.pv_energy_total_kwh = toKwhAuto(value); }
  if (cmd.startsWith("QEY")) { state.pv_energy_year_raw = value; state.pv_energy_year_kwh = toKwhAuto(value); }
  if (cmd.startsWith("QEM")) { state.pv_energy_month_raw = value; state.pv_energy_month_kwh = toKwhAuto(value); }
  if (cmd.startsWith("QED")) { state.pv_energy_day_raw = value; state.pv_energy_day_kwh = toKwhToday(value); }

  if (cmd === "QLT") { state.load_energy_total_raw = value; state.load_energy_total_kwh = toKwhAuto(value); }
  if (cmd.startsWith("QLY")) { state.load_energy_year_raw = value; state.load_energy_year_kwh = toKwhAuto(value); }
  if (cmd.startsWith("QLM")) { state.load_energy_month_raw = value; state.load_energy_month_kwh = toKwhAuto(value); }
  if (cmd.startsWith("QLD")) { state.load_energy_day_raw = value; state.load_energy_day_kwh = toKwhToday(value); }

  state._last_energy_ts = Date.now();
}

// ===== PV total power =====
const pv1 = Number.isFinite(state.pv1_power) ? state.pv1_power : 0;
const pv2 = Number.isFinite(state.pv2_power) ? state.pv2_power : 0;
state.pv_total_power = pv1 + pv2;

// ===== BATTERY POWER (W) =====
const Vb = Number.isFinite(state.battery_voltage) ? state.battery_voltage : null;
const Ichg = Number.isFinite(state.battery_charging_current) ? state.battery_charging_current : 0;
const Idis = Number.isFinite(state.battery_discharge_current) ? state.battery_discharge_current : 0;

if (Vb != null) {
  const chargeW = round(Vb * Math.max(0, Ichg), 1);
  const dischargeW = round(Vb * Math.max(0, Idis), 1);

  state.battery_charge = chargeW;
  state.battery_discharge = dischargeW;
  state.battery_power = (chargeW != null && dischargeW != null) ? round(chargeW - dischargeW, 1) : null;
} else {
  state.battery_charge = null;
  state.battery_discharge = null;
  state.battery_power = null;
}

// ===== TIMEZONE dayKey =====
function localDayKey(d = new Date()) {
  let tz = (global.get("addon_timezone") || "UTC").toString().trim();
  if (!tz) tz = "UTC";
  try {
    new Intl.DateTimeFormat("en-CA", { timeZone: tz }).format(new Date());
  } catch (e) {
    tz = "UTC";
  }

  const parts = new Intl.DateTimeFormat("en-CA", {
    timeZone: tz,
    year: "numeric",
    month: "2-digit",
    day: "2-digit"
  }).formatToParts(d);

  const get = (t) => parts.find(p => p.type === t)?.value;
  return `${get("year")}${get("month")}${get("day")}`;
}

const dayKey = localDayKey(new Date());

// ===== DAILY ENERGY battery =====
const kDay = `inv${inv}_batt_dayKey`;
const kTs  = `inv${inv}_batt_lastTs`;
const kChg = `inv${inv}_batt_lastChargeW`;
const kDis = `inv${inv}_batt_lastDischargeW`;
const kChgWh = `inv${inv}_batt_chargeWh_today`;
const kDisWh = `inv${inv}_batt_dischargeWh_today`;

const lastDay = flow.get(kDay);
let lastTs = flow.get(kTs);
let lastChargeW = flow.get(kChg);
let lastDischargeW = flow.get(kDis);

let chargeWh = flow.get(kChgWh);
let dischargeWh = flow.get(kDisWh);

if (!Number.isFinite(chargeWh)) chargeWh = 0;
if (!Number.isFinite(dischargeWh)) dischargeWh = 0;

if (lastDay && lastDay !== dayKey) {
  chargeWh = 0;
  dischargeWh = 0;
}

const curChargeW = Number.isFinite(state.battery_charge) ? state.battery_charge : 0;
const curDischargeW = Number.isFinite(state.battery_discharge) ? state.battery_discharge : 0;
const nowTs = Date.now();

if (Number.isFinite(lastTs) && Number.isFinite(lastChargeW) && Number.isFinite(lastDischargeW)) {
  const dtMs = nowTs - lastTs;
  if (dtMs > 0 && dtMs <= 10 * 60 * 1000) {
    const dtH = dtMs / 3600000;
    chargeWh += ((lastChargeW + curChargeW) / 2) * dtH;
    dischargeWh += ((lastDischargeW + curDischargeW) / 2) * dtH;
  }
}

flow.set(kDay, dayKey);
flow.set(kTs, nowTs);
flow.set(kChg, curChargeW);
flow.set(kDis, curDischargeW);
flow.set(kChgWh, chargeWh);
flow.set(kDisWh, dischargeWh);

state.battery_charge_day_kwh = Math.round((chargeWh / 1000) * 100) / 100;
state.battery_discharge_day_kwh = Math.round((dischargeWh / 1000) * 100) / 100;
state._day_key = dayKey;

// ===== FILTRES DEMANDÉS =====

// W > 15000 => garde dernière valeur valide
sanitizeW("ac_output_apparent_power", { allowNegative: false, forceNonNegative: true, forceInt: true });
sanitizeW("ac_output_active_power", { allowNegative: false, forceNonNegative: true, forceInt: true });
sanitizeW("pv1_power", { allowNegative: false, forceNonNegative: true, forceInt: true });
sanitizeW("pv2_power", { allowNegative: false, forceNonNegative: true, forceInt: true });
sanitizeW("pv_total_power", { allowNegative: false, forceNonNegative: true, forceInt: true });
sanitizeW("grid_power", { allowNegative: true, forceNonNegative: false, forceInt: true });
sanitizeW("battery_charge", { allowNegative: false, forceNonNegative: true, forceInt: false });
sanitizeW("battery_discharge", { allowNegative: false, forceNonNegative: true, forceInt: false });
sanitizeW("battery_power", { allowNegative: true, forceNonNegative: false, forceInt: false });

// A > 350 => garde dernière valeur valide
sanitizeA("battery_charging_current", { allowNegative: false, forceNonNegative: true, decimals: 1 });
sanitizeA("battery_discharge_current", { allowNegative: false, forceNonNegative: true, decimals: 1 });
sanitizeA("pv1_input_current", { allowNegative: false, forceNonNegative: true, decimals: 1 });
sanitizeA("pv2_input_current", { allowNegative: false, forceNonNegative: true, decimals: 1 });
sanitizeA("global_current", { allowNegative: true, forceNonNegative: false, decimals: 1 });
sanitizeA("inverter_output_current", { allowNegative: false, forceNonNegative: true, decimals: 1 });

// % batterie > 100 => garde dernière valeur valide
sanitizePct("battery_capacity");
if (state.params?.qdop) {
  if (state.params.qdop.battery_recharge_capacity_pct != null) {
    const tmp = finiteNumber(state.params.qdop.battery_recharge_capacity_pct);
    const k = `inv${inv}_last_ok_params_qdop_battery_recharge_capacity_pct`;
    const lastOk = flow.get(k);
    if (tmp != null && tmp >= 0 && tmp <= 100) {
      state.params.qdop.battery_recharge_capacity_pct = Math.trunc(tmp);
      flow.set(k, Math.trunc(tmp));
    } else {
      state.params.qdop.battery_recharge_capacity_pct = Number.isFinite(lastOk) ? lastOk : null;
    }
  }

  if (state.params.qdop.battery_redischarge_capacity_pct != null) {
    const tmp = finiteNumber(state.params.qdop.battery_redischarge_capacity_pct);
    const k = `inv${inv}_last_ok_params_qdop_battery_redischarge_capacity_pct`;
    const lastOk = flow.get(k);
    if (tmp != null && tmp >= 0 && tmp <= 100) {
      state.params.qdop.battery_redischarge_capacity_pct = Math.trunc(tmp);
      flow.set(k, Math.trunc(tmp));
    } else {
      state.params.qdop.battery_redischarge_capacity_pct = Number.isFinite(lastOk) ? lastOk : null;
    }
  }

  if (state.params.qdop.battery_under_capacity_pct != null) {
    const tmp = finiteNumber(state.params.qdop.battery_under_capacity_pct);
    const k = `inv${inv}_last_ok_params_qdop_battery_under_capacity_pct`;
    const lastOk = flow.get(k);
    if (tmp != null && tmp >= 0 && tmp <= 100) {
      state.params.qdop.battery_under_capacity_pct = Math.trunc(tmp);
      flow.set(k, Math.trunc(tmp));
    } else {
      state.params.qdop.battery_under_capacity_pct = Number.isFinite(lastOk) ? lastOk : null;
    }
  }
}

// ===== GRID TODAY (kWh) =====
const kGDay = `inv${inv}_grid_dayKey`;
const kGTs  = `inv${inv}_grid_lastTs`;
const kGLastW = `inv${inv}_grid_lastW`;
const kGWh = `inv${inv}_grid_Wh_today`;

let gLastDay = flow.get(kGDay);
let gLastTs = flow.get(kGTs);
let gLastW = flow.get(kGLastW);
let gWh = flow.get(kGWh);

if (!Number.isFinite(gWh)) gWh = 0;

if (gLastDay && gLastDay !== dayKey) {
  gWh = 0;
}

const gCurW_raw = Number.isFinite(state.grid_power) ? state.grid_power : 0;
const gCurW = Math.max(0, gCurW_raw);
const gNowTs = Date.now();

if (Number.isFinite(gLastTs) && Number.isFinite(gLastW)) {
  const dtMs = gNowTs - gLastTs;
  if (dtMs > 0 && dtMs <= 10 * 60 * 1000) {
    const dtH = dtMs / 3600000;
    gWh += ((gLastW + gCurW) / 2) * dtH;
  }
}

flow.set(kGDay, dayKey);
flow.set(kGTs, gNowTs);
flow.set(kGLastW, gCurW);
flow.set(kGWh, gWh);

state.grid_energy_day_kwh = Math.round((gWh / 1000) * 100) / 100;

// ===== COMMAND SUPPORT DIAGNOSTICS =====

function readCmdSupport(cmd) {
  const key = `inv${inv}_cmd_state_${cmd}`;
  const st = flow.get(key) || {};

  return {
    disabled: st.disabled === true,
    nak_count: Number(st.nak_count || 0),
    last_ok: Number(st.last_ok || 0),
    last_nak: Number(st.last_nak || 0),
    retry_after: Number(st.retry_after || 0)
  };
}

state.diag = state.diag || {};
state.diag.command_support = {

  qpigs2: readCmdSupport("QPIGS2"),

  qet: readCmdSupport("QET"),
  qey: readCmdSupport("QEY"),
  qem: readCmdSupport("QEM"),
  qed: readCmdSupport("QED"),

  qlt: readCmdSupport("QLT"),
  qly: readCmdSupport("QLY"),
  qlm: readCmdSupport("QLM"),
  qld: readCmdSupport("QLD")

};

context.set("state", state);
flow.set(`inv${inv}_normalized_state`, state);
msg.inverterNum = inv;
msg.payload = state;
return msg;

// ===============================
// MQTT STATE PUBLISHER (STABLE JSON)
// Garantit une structure toujours identique
// ===============================

if (!msg.payload || typeof msg.payload !== "object") return null;

const inv = msg.inverterNum ?? 1;
const data = { ...msg.payload };

// -------------------------------------------------
// Helpers
// -------------------------------------------------
const ensure = (obj, key, value = null) => {
  if (obj[key] === undefined) obj[key] = value;
};

// -------------------------------------------------
// 1) STRUCTURE PRINCIPALE
// -------------------------------------------------
ensure(data, "grid_voltage");
ensure(data, "grid_frequency");
ensure(data, "ac_output_voltage");
ensure(data, "ac_output_frequency");
ensure(data, "ac_output_active_power");
ensure(data, "ac_output_apparent_power");
ensure(data, "inverter_output_current");
ensure(data, "output_load_percent");

ensure(data, "battery_voltage");
ensure(data, "battery_charging_current");
ensure(data, "battery_discharge_current");
ensure(data, "battery_capacity");
ensure(data, "global_current");

ensure(data, "battery_charge");
ensure(data, "battery_discharge");
ensure(data, "battery_power");
ensure(data, "battery_charge_day_kwh");
ensure(data, "battery_discharge_day_kwh");

ensure(data, "pv_total_power");
ensure(data, "pv1_power");
ensure(data, "pv2_power");

ensure(data, "pv1_input_voltage");
ensure(data, "pv2_input_voltage");
ensure(data, "pv1_input_current");
ensure(data, "pv2_input_current");

ensure(data, "grid_power");
ensure(data, "grid_energy_day_kwh");
ensure(data, "inverter_heat_sink_temp");

ensure(data, "operation_mode");
ensure(data, "operation_mode_code");
ensure(data, "supports_qpigs2");

// -------------------------------------------------
// 2) ENERGIES
// -------------------------------------------------
ensure(data, "load_energy_month_kwh");
ensure(data, "load_energy_year_kwh");
ensure(data, "load_energy_day_kwh");
ensure(data, "load_energy_total_kwh");

ensure(data, "pv_energy_month_kwh");
ensure(data, "pv_energy_year_kwh");
ensure(data, "pv_energy_day_kwh");
ensure(data, "pv_energy_total_kwh");

// -------------------------------------------------
// 3) DIAG
// -------------------------------------------------
if (!data.diag || typeof data.diag !== "object") data.diag = {};

ensure(data.diag, "model", "unknown");
ensure(data.diag, "serial", "unknown");
ensure(data.diag, "fw_main", "unknown");
ensure(data.diag, "fw_remote", "unknown");

ensure(data.diag, "fault_state", "unknown");
ensure(data.diag, "fault_details", "unknown");
ensure(data.diag, "warn_state", "unknown");
ensure(data.diag, "warn_details", "unknown");

// raw / debug
ensure(data.diag, "raw_command", "");
ensure(data.diag, "raw_response", "");
ensure(data.diag, "raw_response_hex", "");
ensure(data.diag, "_last_raw_command_ts", 0);
ensure(data.diag, "_last_raw_response_ts", 0);
ensure(data.diag, "_last_raw_response_hex_ts", 0);

// support commandes
if (!data.diag.command_support || typeof data.diag.command_support !== "object") {
  data.diag.command_support = {};
}

function ensureCmdSupport(obj, key) {
  if (!obj[key] || typeof obj[key] !== "object") obj[key] = {};
  ensure(obj[key], "disabled", false);
  ensure(obj[key], "nak_count", 0);
  ensure(obj[key], "last_ok", 0);
  ensure(obj[key], "last_nak", 0);
  ensure(obj[key], "retry_after", 0);
}

ensureCmdSupport(data.diag.command_support, "qpigs2");
ensureCmdSupport(data.diag.command_support, "qet");
ensureCmdSupport(data.diag.command_support, "qey");
ensureCmdSupport(data.diag.command_support, "qem");
ensureCmdSupport(data.diag.command_support, "qed");
ensureCmdSupport(data.diag.command_support, "qlt");
ensureCmdSupport(data.diag.command_support, "qly");
ensureCmdSupport(data.diag.command_support, "qlm");
ensureCmdSupport(data.diag.command_support, "qld");

// -------------------------------------------------
// 4) PARAMS
// -------------------------------------------------
if (!data.params || typeof data.params !== "object") data.params = {};
if (!data.params.qpiri || typeof data.params.qpiri !== "object") data.params.qpiri = {};
if (!data.params.qdop || typeof data.params.qdop !== "object") data.params.qdop = {};

const qpiri = data.params.qpiri;
const qdop = data.params.qdop;

ensure(qpiri, "battery_type");
ensure(qpiri, "battery_type_code");

ensure(qpiri, "output_source_priority");
ensure(qpiri, "output_source_priority_code");

ensure(qpiri, "charger_source_priority");
ensure(qpiri, "charger_source_priority_code");

ensure(qpiri, "battery_bulk_voltage");
ensure(qpiri, "battery_float_voltage");
ensure(qpiri, "battery_re_discharge_voltage");
ensure(qpiri, "battery_recharge_voltage");
ensure(qpiri, "battery_under_voltage");

ensure(qpiri, "max_ac_charging_current");
ensure(qpiri, "max_charging_current");
ensure(qpiri, "max_discharging_current");
ensure(qpiri, "ts", 0);

ensure(qdop, "battery_recharge_capacity_pct");
ensure(qdop, "battery_redischarge_capacity_pct");
ensure(qdop, "battery_under_capacity_pct");
ensure(qdop, "ts", 0);

// -------------------------------------------------
// 5) PUBLISH MQTT
// -------------------------------------------------
return [
  {
    topic: `voltronic/${inv}/state`,
    payload: JSON.stringify(data),
    retain: true
  },
  {
    topic: `voltronic/${inv}/availability`,
    payload: "online",
    retain: true
  }
];

const inv = msg.inverterNum ?? 1;

const qKey = `inv${inv}_queue`;
const inFlightKey = `inv${inv}_inflight`;

let q = flow.get(qKey);
if (!Array.isArray(q)) q = [];

const inFlight = flow.get(inFlightKey);
const now = Date.now();

// -------------------------------------------------
// Helpers
// -------------------------------------------------
function getQpigs2State() {
    const qpKey = `inv${inv}_qpigs2_state`;
    let st = flow.get(qpKey);

    if (!st || typeof st !== "object") {
        st = {
            fail_count: 0,
            disabled: false,
            last_try: 0,
            last_ok: 0,
            last_fail: 0,
            reason: ""
        };
        flow.set(qpKey, st);
    }

    return st;
}

function asArray(input) {
    if (Array.isArray(input)) return input;
    if (Array.isArray(input?.payload) && input.payload?.[0]?.command) return input.payload;
    return [input];
}

function cleanStr(v) {
    return String(v ?? "").trim();
}

function normalizeCmd(m) {
    if (!m || typeof m !== "object") return null;

    const rawCommand = cleanStr(m._raw_command || m.command || m._cmd || m.payload);
    const cmd = rawCommand.toUpperCase();

    if (!cmd) return null;

    const origin = cleanStr(m._origin);
    const isPriority =
        origin === "ha_set" ||
        origin === "learn_retry";

    return {
        inverterNum: m.inverterNum ?? inv,
        command: cmd,
        _cmd: cmd,
        _raw_command: rawCommand || cmd,
        payload: cmd,

        _origin: origin,
        _burst: m._burst === true,
        _learn: m._learn || null,
        _qpigs2_probe: m._qpigs2_probe === true,

        // debug / suivi
        enqueued_ts: now,
        priority: isPriority
    };
}

function getDedupeKey(item) {
    return String(item.command || "").trim().toUpperCase();
}

// -------------------------------------------------
// Prépare la liste à ajouter
// -------------------------------------------------
const incoming = asArray(msg);
const toPush = [];

for (const m of incoming) {
    const item = normalizeCmd(m);
    if (!item) continue;
    toPush.push(item);
}

// -------------------------------------------------
// Ajout dans la queue
// -------------------------------------------------
let added = 0;
let dropped = 0;

for (const item of toPush) {
    const cmd = item.command;
    const dedupeKey = getDedupeKey(item);

    // ---------------------------------------------
    // Règle spéciale QPIGS2
    // ---------------------------------------------
    if (cmd === "QPIGS2") {
        const st = getQpigs2State();

        if (st.disabled && item._qpigs2_probe !== true) {
            dropped++;
            continue;
        }
    }

    // ---------------------------------------------
    // Anti-doublon queue
    // ---------------------------------------------
    const alreadyQueued = q.some(x => {
        if (!x) return false;
        return getDedupeKey(x) === dedupeKey;
    });

    // ---------------------------------------------
    // Anti-doublon inflight
    // ---------------------------------------------
    const alreadyInFlight =
        inFlight &&
        String(inFlight.cmd || "").trim().toUpperCase() === dedupeKey;

    // ---------------------------------------------
    // Règles priorité
    // - priorité = passe devant
    // - mais pas en doublon strict
    // ---------------------------------------------
    if (alreadyQueued || alreadyInFlight) {
        dropped++;
        continue;
    }

    if (item.priority) {
        q.unshift(item);
    } else {
        q.push(item);
    }

    added++;
}

// -------------------------------------------------
// Limite de taille
// - on garde le début de queue (priorités déjà devant)
// -------------------------------------------------
if (q.length > 200) {
    q = q.slice(0, 200);
}

flow.set(qKey, q);

node.status({
    fill: "blue",
    shape: "dot",
    text: `q:${q.length} +${added}${dropped ? ` -${dropped}` : ""}`
});

// déclenche le pump
return {
    inverterNum: inv,
    topic: "pump"
};

// HA SET -> Voltronic CMD
// 2 sorties:
//   1) paramètres gérés par apprentissage
//   2) commandes directes vers Queue Enqueue
//
// topic: voltronic/<inv>/set/<param>
// payload: valeur

const m = String(msg.topic || "").match(/^voltronic\/(\d+)\/set\/(.+)$/);
if (!m) return null;

const inverterNum = Number(m[1]);
const param = String(m[2] || "").trim();

if (!Number.isFinite(inverterNum) || !param) return null;

// -------------------------------------------------
// Normalisation payload
// -------------------------------------------------
function cleanString(v) {
  let s = String(v ?? "").trim();
  if (!s) return "";

  s = s.replace(/^"+|"+$/g, "");

  try {
    if (
      (s.startsWith('\\"')) ||
      (s.startsWith('"') && s.endsWith('"'))
    ) {
      const parsed = JSON.parse(s);
      if (typeof parsed === "string") s = parsed;
    }
  } catch (e) {
    // ignore
  }

  return String(s ?? "").trim().replace(/^"+|"+$/g, "");
}

let v = msg.payload;
if (typeof v === "string") {
  v = cleanString(v);
}

// -------------------------------------------------
// Helpers
// -------------------------------------------------
const toNum = (x) => {
  if (x == null) return null;

  if (typeof x === "string") {
    const s = cleanString(x);
    const m = s.match(/-?\d+(\.\d+)?/);
    if (!m) return null;
    x = m[0];
  }

  const n = Number(x);
  return Number.isFinite(n) ? n : null;
};

const clamp = (x, a, b) => Math.min(b, Math.max(a, Number(x)));
const pad3 = (x) => String(Math.trunc(Number(x))).padStart(3, "0");
const fixed1 = (x) => Number(x).toFixed(1);

const mk = (c, extra = {}) => ({
  inverterNum,
  command: c,
  _cmd: c,
  payload: c,
  _burst: true,
  _origin: extra._origin || "ha_set",
  ...extra
});

function getParallelId(inv) {
  let machine = flow.get(`inv${inv}_parallel_id`);
  if (machine === undefined || machine === null || machine === "") machine = 0;
  machine = Number(machine);
  if (!Number.isFinite(machine) || machine < 0 || machine > 9) machine = 0;
  return machine;
}

function canonLearnParam(p) {
  const s = cleanString(p);

  const map = {
    battery_bulk_voltage: "battery_bulk_voltage",
    battery_float_voltage: "battery_float_voltage",

    battery_cutoff_voltage: "battery_under_voltage",
    battery_under_voltage: "battery_under_voltage",

    back_to_grid_voltage: "battery_recharge_voltage",
    battery_recharge_voltage: "battery_recharge_voltage",

    back_to_battery_voltage: "battery_re_discharge_voltage",
    battery_re_discharge_voltage: "battery_re_discharge_voltage",

    max_charging_current: "max_charging_current",

    grid_charging_current: "max_ac_charging_current",
    max_ac_charging_current: "max_ac_charging_current",

    charger_source_priority: "charger_source_priority",
    output_source_priority: "output_source_priority"
  };

  return map[s] || s;
}

function isLearnableParam(p) {
  const lp = canonLearnParam(p);
  return [
    "battery_bulk_voltage",
    "battery_float_voltage",
    "battery_under_voltage",
    "battery_recharge_voltage",
    "battery_re_discharge_voltage",
    "max_charging_current",
    "max_ac_charging_current",
    "charger_source_priority",
    "output_source_priority"
  ].includes(lp);
}

// -------------------------------------------------
// Priorités -> slot canonique interne
// On ne travaille PAS sur les labels ensuite.
// output_source_priority -> slots 0 / 1 / 2
// charger_source_priority -> slots 0 / 1 / 2
// -------------------------------------------------
function normKey(v) {
  return cleanString(v)
    .toLowerCase()
    .replace(/\s+/g, "")
    .replace(/\+/g, "plus");
}

function getOutputPrioritySlot(v) {
  const raw = cleanString(v);
  const key = normKey(v);

  if (raw === "0" || key === "0") return 0;
  if (raw === "1" || key === "1") return 1;
  if (raw === "2" || key === "2") return 2;

  const map = {
    utilitysolarbat: 0,
    usb: 0,

    solarutilitybat: 1,
    sub: 1,

    solarbatutility: 2,
    sbu: 2
  };

  return Number.isInteger(map[key]) ? map[key] : null;
}

function getChargerPrioritySlot(v) {
  const raw = cleanString(v);
  const key = normKey(v);

  if (raw === "0" || key === "0") return 0;
  if (raw === "1" || key === "1") return 1;
  if (raw === "2" || key === "2") return 2;

  const map = {
    solarfirst: 0,
    cso: 0,

    solarplusutility: 1,
    solarutility: 1,
    snu: 1,

    onlysolar: 2,
    oso: 2
  };

  return Number.isInteger(map[key]) ? map[key] : null;
}

// -------------------------------------------------
// RAW COMMAND MANUELLE
// -------------------------------------------------
if (param === "raw_command") {
  const cmd = cleanString(v).toUpperCase();
  if (!cmd) return null;

  const rawMsg = mk(cmd, {
    _burst: false,
    _origin: "ha_set",
    _raw_manual: true,
    _raw_command: cmd
  });

  node.status({
    fill: "yellow",
    shape: "dot",
    text: `RAW ${cmd}`
  });

  return [null, [rawMsg]];
}

// -------------------------------------------------
// PARAMÈTRES APPRENABLES
// -------------------------------------------------
if (isLearnableParam(param)) {
  const learnParam = canonLearnParam(param);

  let learnValue = v;
  let learnMode = "number";

  if (learnParam === "output_source_priority") {
    const slot = getOutputPrioritySlot(v);
    if (slot == null) return null;
    learnValue = slot;
    learnMode = "enum_profile";
  }

  if (learnParam === "charger_source_priority") {
    const slot = getChargerPrioritySlot(v);
    if (slot == null) return null;
    learnValue = slot;
    learnMode = "enum_profile";
  }

  const learnMsg = {
    inverterNum,
    topic: msg.topic,
    payload: learnValue,
    _origin: "ha_set",
    _ha_param: learnParam,
    _ha_param_raw: param,
    _ha_value: learnValue,
    _ha_value_raw: v,
    _learn_mode: learnMode
  };

  node.status({
    fill: "blue",
    shape: "dot",
    text: `LEARN ${learnParam}`
  });

  return [learnMsg, null];
}

// -------------------------------------------------
// Tables de mapping direct (hors apprentissage)
// -------------------------------------------------
const batteryTypeMap = {
  AGM: "PBT00",
  Flooded: "PBT01",
  User: "PBT02",
  Pylon: "PBT03",
  Weco: "PBT05",
  Soltaro: "PBT06",
  Lib: "PBT08",
  Lic: "PBT09"
};

// -------------------------------------------------
// Résolution commande directe
// -------------------------------------------------
const machine = getParallelId(inverterNum);

let cmd = null;
let refresh = ["QMOD", "QPIGS"];

if (param === "battery_type") {
  const sv = cleanString(v);
  cmd = batteryTypeMap[sv] || null;
  refresh = ["QPIRI", "QMOD", "QPIGS"];

} else if (param === "max_discharging_current") {
  const sv = cleanString(v);
  if (sv === "0") return null;

  const nv = toNum(sv);
  if (nv == null) return null;

  cmd = `PBATMAXDISC${pad3(clamp(nv, 1, 200))}`;
  refresh = ["QPIRI", "QPIGS"];

} else if (param === "battery_recharge_capacity_pct") {
  const nv = toNum(v); if (nv == null) return null;
  cmd = `PBCC${pad3(clamp(nv, 5, 95))}`;
  refresh = ["QDOP", "QPIGS"];

} else if (param === "battery_redischarge_capacity_pct") {
  const nv = toNum(v); if (nv == null) return null;
  cmd = `PBDC${pad3(clamp(nv, 10, 100))}`;
  refresh = ["QDOP", "QPIGS"];

} else if (param === "battery_under_capacity_pct") {
  const nv = toNum(v); if (nv == null) return null;
  cmd = `PSDC${pad3(clamp(nv, 0, 90))}`;
  refresh = ["QDOP", "QPIGS"];
}

if (!cmd) return null;

// -------------------------------------------------
// Construction sortie directe
// -------------------------------------------------
const setMsg = mk(cmd, {
  _burst: false,
  _origin: "ha_set",
  _ha_param: param,
  _ha_value: v
});

