                    1: { command: "POP01", expectedCode: 1 },
                    2: { command: "POP02", expectedCode: 2 }
                },
                pop_01_03: {
                    0: { command: "POP01", expectedCode: 1 },
                    1: { command: "POP02", expectedCode: 2 },
                    2: { command: "POP03", expectedCode: 3 }
                }
            }
        },
        charger_source_priority: {
            kind: "enum_profile",
            profiles: {
                pcp_00_02: {
                    0: { command: "PCP00", expectedCode: 0 },
                    1: { command: "PCP01", expectedCode: 1 },
                    2: { command: "PCP02", expectedCode: 2 }
                },
                pcp_01_03: {
                    0: { command: "PCP01", expectedCode: 1 },
                    1: { command: "PCP02", expectedCode: 2 },
                    2: { command: "PCP03", expectedCode: 3 }
                }
            }
        }
    };
}

const sessionKey = `learn_session_inv${inv}`;
const pendingLearnKey = `learn_pending_inv${inv}`;

let session = flow.get(sessionKey);
if (!session || session.active !== true) return null;

const registry = getRegistry(inv);
const cfg = registry[session.param];
if (!cfg) return null;

function buildFailMsg(reason) {
    return {
        inverterNum: inv,
        topic: `voltronic/${inv}/learning/status`,
        payload: {
            active: false,
            success: false,
            reason,
            param: session.param,
            requested_value: session.requestedValue ?? null,
            requested_slot: session.requestedSlot ?? null,
            fingerprint: session.fingerprint,
            finished_at: new Date().toISOString()
        },
        _learn_complete: true,
        _learn_success: false
    };
}

// -------------------------------------------------
// MODE NUMERIQUE
// -------------------------------------------------
if (session.kind === "number") {
    session.index = Number(session.index || -1) + 1;
    session.updatedAt = Date.now();

    if (session.index >= session.candidateKeys.length) {
        node.status({
            fill: "red",
            shape: "ring",
            text: `learn fail ${session.param}`
        });
        return [null, buildFailMsg("no_candidate_left")];
    }

    const wanted = session.candidateKeys[session.index];
    const candidate = cfg.candidates.find(c => c.key === wanted.key);

    if (!candidate || typeof candidate.build !== "function") {
        flow.set(sessionKey, session);
        return [{
            inverterNum: inv,
            _learn_action: "next_candidate"
        }, null];
    }

    const cmd = candidate.build(session.requestedValue);

    session.currentCandidate = {
        mode: "number",
        key: candidate.key,
        source: wanted.source,
        command: cmd,
        sentAt: Date.now()
    };

    session.phase = "wait_ack";
    session.lastAck = null;

    flow.set(sessionKey, session);
    flow.set(pendingLearnKey, {
        sessionId: session.sessionId,
        param: session.param,
        cmd: cmd,
        phase: "wait_ack",
        ts: Date.now()
    });

    const out = {
        inverterNum: inv,
        command: cmd,
        _cmd: cmd,
        _raw_command: cmd,
        payload: cmd,
        _burst: false,
        _origin: "learn_retry",
        _ha_param: session.paramRaw || session.param,
        _ha_value: session.requestedRaw,
        _learn: {
            sessionId: session.sessionId,
            param: session.param,
            requestedValue: session.requestedValue,
            candidateKey: candidate.key,
            source: wanted.source,
            phase: "candidate"
        }
    };

    node.status({
        fill: "yellow",
        shape: "dot",
        text: `learn try ${candidate.key}`
    });

    return [out, null];
}

// -------------------------------------------------
// MODE PROFIL ENUM
// -------------------------------------------------
if (session.kind === "enum_profile") {
    let found = null;

    while (true) {
        session.index = Number(session.index || -1) + 1;
        session.updatedAt = Date.now();

        if (session.index >= session.candidateProfiles.length) {
            node.status({
                fill: "red",
                shape: "ring",
                text: `learn fail ${session.param}`
            });
            return [null, buildFailMsg("no_profile_left")];
        }

        const wanted = session.candidateProfiles[session.index];
        const profile = cfg.profiles?.[wanted.profileKey];
        const slotCfg = profile?.[session.requestedSlot];

        if (slotCfg && slotCfg.command) {
            found = {
                wanted,
                profileKey: wanted.profileKey,
                command: String(slotCfg.command).trim().toUpperCase(),
                expectedCode: Number(slotCfg.expectedCode)
            };
            break;
        }
    }

    session.currentCandidate = {
        mode: "profile",
        profileKey: found.profileKey,
        source: found.wanted.source,
        command: found.command,
        expectedCode: found.expectedCode,
        requestedSlot: session.requestedSlot,
        sentAt: Date.now()
    };

    session.phase = "wait_ack";
    session.lastAck = null;

    flow.set(sessionKey, session);
    flow.set(pendingLearnKey, {
        sessionId: session.sessionId,
        param: session.param,
        cmd: found.command,
        phase: "wait_ack",
        ts: Date.now()
    });

    const out = {
        inverterNum: inv,
        command: found.command,
        _cmd: found.command,
        _raw_command: found.command,
        payload: found.command,
        _burst: false,
        _origin: "learn_retry",
        _ha_param: session.paramRaw || session.param,
        _ha_value: session.requestedRaw,
        _learn: {
            sessionId: session.sessionId,
            param: session.param,
            requestedSlot: session.requestedSlot,
            profileKey: found.profileKey,
            expectedCode: found.expectedCode,
            phase: "candidate"
        }
    };

    node.status({
        fill: "yellow",
        shape: "dot",
        text: `learn try ${found.profileKey}`
    });

    return [out, null];
}

return null;

// ====== LEARNING - RX FEEDBACK ======
// Entrées possibles:
// - Parser sortie 2
// - Queue Pump timeout sortie 2
//
// Sortie 1 = enqueue QPIRI verify
// Sortie 2 = next candidate

const inv = msg.inverterNum ?? 1;
const sessionKey = `learn_session_inv${inv}`;
const pendingLearnKey = `learn_pending_inv${inv}`;

function cleanString(v) {
    return String(v ?? "").trim().toUpperCase();
}

let session = flow.get(sessionKey);
if (!session || session.active !== true) return null;

if (!session.currentCandidate || session.phase !== "wait_ack") {
    return null;
}

const currentCmd = cleanString(session.currentCandidate.command);
const msgCmd = cleanString(msg._raw_command || msg.command || msg._cmd || msg.payload?.raw_command || msg.payload?.command);

// message pas pour la commande actuellement testée
if (msgCmd !== currentCmd) return null;

// timeout remonté par Queue Pump
if (msg._learn_timeout === true || msg.payload?.timeout === true) {
    session.lastAck = "TIMEOUT";
    session.phase = "build";
    session.updatedAt = Date.now();

    flow.set(sessionKey, session);
    flow.set(pendingLearnKey, null);

    node.status({
        fill: "red",
        shape: "ring",
        text: `learn timeout ${session.param}`
    });

    return [null, {
        inverterNum: inv,
        _learn_action: "next_candidate"
    }];
}

const nak = (msg.payload?.nak === true);

if (nak) {
    session.lastAck = "NAK";
    session.phase = "build";
    session.updatedAt = Date.now();

    flow.set(sessionKey, session);
    flow.set(pendingLearnKey, null);

    node.status({
        fill: "yellow",
        shape: "ring",
        text: `learn NAK ${session.currentCandidate.key}`
    });

    return [null, {
        inverterNum: inv,
        _learn_action: "next_candidate"
    }];
}

// ACK ou réponse non-NAK => on force un QPIRI de vérification
session.lastAck = "ACK";
session.phase = "wait_state";
session.verifySentAt = Date.now();
session.updatedAt = Date.now();

flow.set(sessionKey, session);
flow.set(pendingLearnKey, {
    sessionId: session.sessionId,
    param: session.param,
    cmd: "QPIRI",
    phase: "wait_state",
    ts: Date.now()
});

const verifyMsg = {
    inverterNum: inv,
    command: "QPIRI",
    _cmd: "QPIRI",
    _raw_command: "QPIRI",
    payload: "QPIRI",
    _burst: false,
    _origin: "learn_retry",
    _learn: {
        sessionId: session.sessionId,
        param: session.param,
        requestedValue: session.requestedValue,
        candidateKey: session.currentCandidate.key,
        phase: "verify"
    }
};

node.status({
    fill: "blue",
    shape: "dot",
    text: `learn verify ${session.currentCandidate.key}`
});

return [verifyMsg, null];

// ====== LEARNING - STATE FEEDBACK ======
// Sortie 1 = complete success
// Sortie 2 = next candidate

const inv = msg.inverterNum ?? 1;
const sessionKey = `learn_session_inv${inv}`;
const pendingLearnKey = `learn_pending_inv${inv}`;

function getByPath(obj, path) {
    if (!obj || !path) return undefined;
    return path.split(".").reduce((acc, k) => acc && acc[k], obj);
}

function toNum(v) {
    const n = Number(v);
    return Number.isFinite(n) ? n : null;
}

function isEqual(a, b, tol) {
    const na = toNum(a);
    const nb = toNum(b);
    if (na == null || nb == null) return false;
    return Math.abs(na - nb) <= tol;
}

const session = flow.get(sessionKey);
if (!session || session.active !== true) return null;

const cmd = String(msg.command || msg._cmd || "").trim().toUpperCase();
if (cmd !== "QPIRI") return null;

if (session.phase !== "wait_state") return null;

const state = msg.payload || {};

// -------------------------------------------------
// MODE NUMERIQUE
// -------------------------------------------------
if (session.kind === "number") {
    const actualValue = getByPath(state, session.statePath);

    if (isEqual(actualValue, session.requestedValue, session.tolerance)) {
        flow.set(pendingLearnKey, null);

        const okMsg = {
            inverterNum: inv,
            topic: `voltronic/${inv}/learning/status`,
            payload: {
                active: false,
                success: true,
                param: session.param,
                candidate_key: session.currentCandidate?.key || null,
                command: session.currentCandidate?.command || null,
                requested_value: session.requestedValue,
                verified_value: actualValue,
                fingerprint: session.fingerprint,
                finished_at: new Date().toISOString()
            },
            _learn_complete: true,
            _learn_success: true
        };

        node.status({
            fill: "green",
            shape: "dot",
            text: `learn OK ${session.param}`
        });

        return [okMsg, null];
    }

    flow.set(pendingLearnKey, null);

    node.status({
        fill: "yellow",
        shape: "ring",
        text: `learn next ${session.param}`
    });

    return [null, {
        inverterNum: inv,
        _learn_action: "next_candidate"
    }];
}

// -------------------------------------------------
// MODE PROFIL ENUM
// -------------------------------------------------
if (session.kind === "enum_profile") {
    const actualCode = toNum(getByPath(state, session.statePath));
    const expectedCode = toNum(session.currentCandidate?.expectedCode);

    if (actualCode != null && expectedCode != null && actualCode === expectedCode) {
        flow.set(pendingLearnKey, null);

        const okMsg = {
            inverterNum: inv,
            topic: `voltronic/${inv}/learning/status`,
            payload: {
                active: false,
                success: true,
                param: session.param,
                profile_key: session.currentCandidate?.profileKey || null,
                command: session.currentCandidate?.command || null,
                requested_slot: session.requestedSlot,
                verified_code: actualCode,
                expected_code: expectedCode,
                fingerprint: session.fingerprint,
                finished_at: new Date().toISOString()
            },
            _learn_complete: true,
            _learn_success: true
        };

        node.status({
            fill: "green",
            shape: "dot",
            text: `learn OK ${session.param}`
        });

        return [okMsg, null];
    }

    flow.set(pendingLearnKey, null);

    node.status({
        fill: "yellow",
        shape: "ring",
        text: `learn next ${session.param}`
    });

    return [null, {
        inverterNum: inv,
        _learn_action: "next_candidate"
    }];
}

return null;

// ====== LEARNING - COMPLETE ======

const inv = msg.inverterNum ?? 1;
const sessionKey = `learn_session_inv${inv}`;
const pendingLearnKey = `learn_pending_inv${inv}`;

let session = flow.get(sessionKey);

if (!msg._learn_complete) {
    return null;
}

const success = (msg._learn_success === true);

function clone(obj) {
    return JSON.parse(JSON.stringify(obj || {}));
}

function uniqNums(arr) {
    const out = [];
    for (const v of (Array.isArray(arr) ? arr : [])) {
        const n = Number(v);
        if (Number.isFinite(n) && !out.includes(n)) out.push(n);
    }
    return out.sort((a, b) => a - b);
}

// -------------------------------------------------
// SUCCÈS
// -------------------------------------------------
if (success && session && session.active === true && session.fingerprint && session.param) {
    const all = clone(global.get("learned_commands") || {});
    if (!all[session.fingerprint]) all[session.fingerprint] = {};

    const prev = all[session.fingerprint][session.param] || {};

    // ---------- paramètres numériques ----------
    if (session.kind === "number" && session.currentCandidate?.key) {
        all[session.fingerprint][session.param] = {
            key: session.currentCandidate.key,
            learnedAt: Date.now(),
            successCount: Number(prev.successCount || 0) + 1,
            failCount: 0,
            lastValue: session.requestedValue,
            lastCommandExample: session.currentCandidate.command
        };
    }

    // ---------- paramètres profil ----------
    if (session.kind === "enum_profile" && session.currentCandidate?.profileKey) {
        const prevCodes = uniqNums(prev.provenCodes || []);
        const expectedCode = Number(session.currentCandidate.expectedCode);
        const newCodes = uniqNums([...prevCodes, expectedCode]);

        // confirmed seulement quand on a vu un code discriminant 0 ou 3
        const confidence = (newCodes.includes(0) || newCodes.includes(3))
            ? "confirmed"
            : "tentative";

        all[session.fingerprint][session.param] = {
            mode: "profile",
            profileKey: session.currentCandidate.profileKey,
            confidence,
            provenCodes: newCodes,
            learnedAt: Date.now(),
            successCount: Number(prev.successCount || 0) + 1,
            failCount: 0,
            lastSlot: session.requestedSlot,
            lastExpectedCode: expectedCode,
            lastCommandExample: session.currentCandidate.command
        };
    }

    global.set("learned_commands", all);
}

// -------------------------------------------------
// ÉCHEC
// -------------------------------------------------
if (!success && session && session.fingerprint && session.param) {
    const all = clone(global.get("learned_commands") || {});
    const fp = all[session.fingerprint] || {};
    const entry = fp[session.param];

    if (entry) {
        entry.failCount = Number(entry.failCount || 0) + 1;

        // après 3 échecs, on oublie l'apprentissage
        if (entry.failCount >= 3) {
            delete fp[session.param];
        }

        all[session.fingerprint] = fp;
        global.set("learned_commands", all);
    }
}

flow.set(pendingLearnKey, null);
flow.set(sessionKey, null);

const historyKey = `learn_history_inv${inv}`;
let hist = flow.get(historyKey);
if (!Array.isArray(hist)) hist = [];

hist.unshift({
    ts: Date.now(),
    success,
    kind: session?.kind || null,
    param: session?.param || msg.payload?.param || null,
    candidate_key: session?.currentCandidate?.key || msg.payload?.candidate_key || null,
    profile_key: session?.currentCandidate?.profileKey || msg.payload?.profile_key || null,
    command: session?.currentCandidate?.command || msg.payload?.command || null,
    requested_value: session?.requestedValue ?? msg.payload?.requested_value ?? null,
    requested_slot: session?.requestedSlot ?? msg.payload?.requested_slot ?? null,
    expected_code: session?.currentCandidate?.expectedCode ?? msg.payload?.expected_code ?? null,
    fingerprint: session?.fingerprint || msg.payload?.fingerprint || null
});

if (hist.length > 30) hist = hist.slice(0, 30);
flow.set(historyKey, hist);

node.status({
    fill: success ? "green" : "red",
    shape: success ? "dot" : "ring",
    text: success ? "learn saved" : "learn failed"
});

return msg;

// ====== LEARNING - PREPROCESS ======
// Sortie 1 = apprentissage
// Sortie 2 = bypass direct

const inv = msg.inverterNum ?? 1;

function cleanString(v) {
    return String(v ?? "").trim();
}

function toNum(x) {
    if (x == null) return null;
    if (typeof x === "string") {
        const s = cleanString(x);
        const m = s.match(/-?\d+(\.\d+)?/);
        if (!m) return null;
        x = m[0];
    }
    const n = Number(x);
    return Number.isFinite(n) ? n : null;
}

function getByPath(obj, path) {
    if (!obj || !path) return undefined;
    return path.split(".").reduce((acc, k) => acc && acc[k], obj);
}

function getFingerprint(state) {
    const model = cleanString(state?.diag?.model);
    const serial = cleanString(state?.diag?.serial);
    if (!model || !serial) return "";
    return `${model}|${serial}`;
}

function canonParam(p) {
    const map = {
        battery_bulk_voltage: "battery_bulk_voltage",
        battery_float_voltage: "battery_float_voltage",

        battery_cutoff_voltage: "battery_under_voltage",
        battery_under_voltage: "battery_under_voltage",

        back_to_grid_voltage: "battery_recharge_voltage",
        battery_recharge_voltage: "battery_recharge_voltage",

        back_to_battery_voltage: "battery_re_discharge_voltage",
        battery_re_discharge_voltage: "battery_re_discharge_voltage",

        max_charging_current: "max_charging_current",

        grid_charging_current: "max_ac_charging_current",
        max_ac_charging_current: "max_ac_charging_current",

        charger_source_priority: "charger_source_priority",
        output_source_priority: "output_source_priority"
    };

    return map[cleanString(p)] || cleanString(p);
}

function getRegistry() {
    return {
        battery_bulk_voltage: {
            kind: "number",
            statePath: "params.qpiri.battery_bulk_voltage",
            tolerance: 0.05
        },
        battery_float_voltage: {
            kind: "number",
            statePath: "params.qpiri.battery_float_voltage",
            tolerance: 0.05
        },
        battery_under_voltage: {
            kind: "number",
            statePath: "params.qpiri.battery_under_voltage",
            tolerance: 0.05
        },
        battery_recharge_voltage: {
            kind: "number",
            statePath: "params.qpiri.battery_recharge_voltage",
            tolerance: 0.05
        },
        battery_re_discharge_voltage: {
            kind: "number",
            statePath: "params.qpiri.battery_re_discharge_voltage",
            tolerance: 0.05
        },
        max_charging_current: {
            kind: "number",
            statePath: "params.qpiri.max_charging_current",
            tolerance: 0.5
        },
        max_ac_charging_current: {
            kind: "number",
            statePath: "params.qpiri.max_ac_charging_current",
            tolerance: 0.5
        },
        charger_source_priority: {
            kind: "enum_profile",
            statePath: "params.qpiri.charger_source_priority_code"
        },
        output_source_priority: {
            kind: "enum_profile",
            statePath: "params.qpiri.output_source_priority_code"
        }
    };
}

function isEqual(a, b, tol) {
    const na = Number(a);
    const nb = Number(b);
    if (!Number.isFinite(na) || !Number.isFinite(nb)) return false;
    return Math.abs(na - nb) <= tol;
}

const paramRaw = cleanString(msg._ha_param || msg.topic || "");
const valueRaw = msg._ha_value ?? msg.payload;
const param = canonParam(paramRaw);

const registry = getRegistry();
const cfg = registry[param];

// param non géré par apprentissage => bypass
if (!cfg) {
    return [null, msg];
}

const sessionKey = `learn_session_inv${inv}`;
const existing = flow.get(sessionKey);

if (existing && existing.active === true) {
    node.status({
        fill: "yellow",
        shape: "ring",
        text: `learn busy ${existing.param}`
    });
    return [null, null];
}

const state = flow.get(`inv${inv}_normalized_state`) || {};
const fingerprint = getFingerprint(state);

// si fingerprint absent, bypass
if (!fingerprint) {
    node.status({
        fill: "yellow",
        shape: "dot",
        text: "learn bypass no fingerprint"
    });
    return [null, msg];
}

const currentValue = getByPath(state, cfg.statePath);

if (cfg.kind === "number") {
    const requestedValue = toNum(valueRaw);
    if (requestedValue == null) {
        node.status({ fill: "red", shape: "ring", text: `learn invalid ${param}` });
        return [null, null];
    }

    // déjà à la bonne valeur
    if (isEqual(currentValue, requestedValue, cfg.tolerance)) {
        node.status({
            fill: "green",
            shape: "dot",
            text: `already ${param}=${requestedValue}`
        });
        return [null, null];
    }

    msg._learn = {
        active: true,
        sessionId: `inv${inv}_${param}_${Date.now()}`,
        inverterNum: inv,
        param,
        paramRaw: cleanString(msg._ha_param_raw || msg._ha_param || param),
        requestedValue,
        requestedRaw: msg._ha_value_raw ?? valueRaw,
        baselineValue: currentValue,
        fingerprint,
        statePath: cfg.statePath,
        tolerance: cfg.tolerance,
        kind: "number",
        createdAt: Date.now()
    };

    node.status({
        fill: "blue",
        shape: "dot",
        text: `learn ${param} -> ${requestedValue}`
    });

    return [msg, null];
}

if (cfg.kind === "enum_profile") {
    const requestedSlot = Number(valueRaw);
    if (!Number.isInteger(requestedSlot) || requestedSlot < 0 || requestedSlot > 2) {
        node.status({ fill: "red", shape: "ring", text: `learn invalid slot ${param}` });
        return [null, null];
    }

    msg._learn = {
        active: true,
        sessionId: `inv${inv}_${param}_${Date.now()}`,
        inverterNum: inv,
        param,
        paramRaw: cleanString(msg._ha_param_raw || msg._ha_param || param),
        requestedSlot,
        requestedRaw: msg._ha_value_raw ?? valueRaw,
        baselineValue: currentValue,
        fingerprint,
        statePath: cfg.statePath,
        kind: "enum_profile",
        createdAt: Date.now()
    };

    node.status({
        fill: "blue",
        shape: "dot",
        text: `learn ${param} slot ${requestedSlot}`
    });

    return [msg, null];
}

return [null, msg];

// ====== LEARNING - DECISION ======

const inv = msg.inverterNum ?? 1;
if (!msg._learn || typeof msg._learn !== "object") return null;

function cleanString(v) {
    return String(v ?? "").trim();
}

function getParallelId(inv) {
    let machine = flow.get(`inv${inv}_parallel_id`);
    if (machine === undefined || machine === null || machine === "") machine = 0;
    machine = Number(machine);
    if (!Number.isFinite(machine) || machine < 0 || machine > 9) machine = 0;
    return machine;
}

function pad3(x) {
    return String(Math.trunc(Number(x))).padStart(3, "0");
}

function fixed1(x) {
    return Number(x).toFixed(1);
}

function getRegistry(inv) {
    const machine = getParallelId(inv);

    return {
        battery_bulk_voltage: {
            kind: "number",
            candidates: [
                { key: "BULK_PCVV_1DEC", build: (v) => `PCVV${fixed1(v)}` }
            ]
        },
        battery_float_voltage: {
            kind: "number",
            candidates: [
                { key: "FLOAT_PBFT_1DEC", build: (v) => `PBFT${fixed1(v)}` }
            ]
        },
        battery_under_voltage: {
            kind: "number",
            candidates: [
                { key: "UNDER_PSDV_1DEC", build: (v) => `PSDV${fixed1(v)}` }
            ]
        },
        battery_recharge_voltage: {
            kind: "number",
            candidates: [
                { key: "BACK_TO_GRID_PBCV_1DEC", build: (v) => `PBCV${fixed1(v)}` }
            ]
        },
        battery_re_discharge_voltage: {
            kind: "number",
            candidates: [
                { key: "BACK_TO_BATTERY_PBDV_1DEC", build: (v) => `PBDV${fixed1(v)}` }
            ]
        },
        max_charging_current: {
            kind: "number",
            candidates: [
                { key: "MAX_CHG_MNCHGC_MACHINE", build: (v) => `MNCHGC${machine}${pad3(v)}` },
                { key: "MAX_CHG_MNCHGC_RAW", build: (v) => `MNCHGC${pad3(v)}` }
            ]
        },
        max_ac_charging_current: {
            kind: "number",
            candidates: [
                { key: "GRID_CHG_MUCHGC_MACHINE", build: (v) => `MUCHGC${machine}${pad3(v)}` },
                { key: "GRID_CHG_MUCHGC_RAW", build: (v) => `MUCHGC${pad3(v)}` }
            ]
        },

        // ---- profils output priority ----
        output_source_priority: {
            kind: "enum_profile",
            profiles: {
                pop_00_02: {
                    0: { command: "POP00", expectedCode: 0 },
                    1: { command: "POP01", expectedCode: 1 },
                    2: { command: "POP02", expectedCode: 2 }
                },
                pop_01_03: {
                    0: { command: "POP01", expectedCode: 1 },
                    1: { command: "POP02", expectedCode: 2 },
                    2: { command: "POP03", expectedCode: 3 }
                }
            }
        },

        // ---- profils charger priority ----
        charger_source_priority: {
            kind: "enum_profile",
            profiles: {
                pcp_00_02: {
                    0: { command: "PCP00", expectedCode: 0 },
                    1: { command: "PCP01", expectedCode: 1 },
                    2: { command: "PCP02", expectedCode: 2 }
                },
                pcp_01_03: {
                    0: { command: "PCP01", expectedCode: 1 },
                    1: { command: "PCP02", expectedCode: 2 },
                    2: { command: "PCP03", expectedCode: 3 }
                }
            }
        }
    };
}

const registry = getRegistry(inv);
const param = msg._learn.param;
const cfg = registry[param];
if (!cfg) return null;

const learnedAll = global.get("learned_commands") || {};
const fp = msg._learn.fingerprint;
const learnedForFp = learnedAll[fp] || {};
const learnedEntry = learnedForFp[param] || null;

const session = {
    active: true,
    sessionId: msg._learn.sessionId,
    inverterNum: inv,
    param: param,
    paramRaw: msg._learn.paramRaw,
    requestedRaw: msg._learn.requestedRaw,
    baselineValue: msg._learn.baselineValue,
    fingerprint: fp,
    statePath: msg._learn.statePath,
    kind: msg._learn.kind,
    createdAt: msg._learn.createdAt || Date.now(),
    updatedAt: Date.now(),
    index: -1,
    currentCandidate: null,
    phase: "build",
    lastAck: null,
    verifySentAt: 0
};

if (msg._learn.kind === "number") {
    session.requestedValue = msg._learn.requestedValue;
    session.tolerance = msg._learn.tolerance;

    let ordered = [];

    if (learnedEntry && learnedEntry.key) {
        ordered.push({
            kind: "number_candidate",
            key: learnedEntry.key,
            source: "learned"
        });
    }

    for (const c of cfg.candidates) {
        if (!ordered.some(x => x.key === c.key)) {
            ordered.push({
                kind: "number_candidate",
                key: c.key,
                source: "registry"
            });
        }
    }

    session.candidateKeys = ordered;
}

if (msg._learn.kind === "enum_profile") {
    session.requestedSlot = msg._learn.requestedSlot;

    let orderedProfiles = [];

    if (learnedEntry && learnedEntry.mode === "profile" && learnedEntry.profileKey) {
        orderedProfiles.push({
            kind: "profile_candidate",
            profileKey: learnedEntry.profileKey,
            source: "learned",
            confidence: learnedEntry.confidence || "tentative",
            provenCodes: Array.isArray(learnedEntry.provenCodes) ? learnedEntry.provenCodes : []
        });
    }

    for (const profileKey of Object.keys(cfg.profiles || {})) {
        if (!orderedProfiles.some(x => x.profileKey === profileKey)) {
            orderedProfiles.push({
                kind: "profile_candidate",
                profileKey,
                source: "registry",
                confidence: "unknown",
                provenCodes: []
            });
        }
    }

    session.candidateProfiles = orderedProfiles;
}

flow.set(`learn_session_inv${inv}`, session);

msg._learn_action = "next_candidate";

node.status({
    fill: "blue",
    shape: "dot",
    text: `learn decision ${param}`
});

return msg;

// ====== LEARNING - RX FEEDBACK ======
// Entrées possibles:
// - Parser sortie 2
// - Queue Pump timeout sortie 2
//
// Sortie 1 = enqueue QPIRI verify
// Sortie 2 = next candidate

const inv = msg.inverterNum ?? 1;
const sessionKey = `learn_session_inv${inv}`;
const pendingLearnKey = `learn_pending_inv${inv}`;

function cleanString(v) {
    return String(v ?? "").trim().toUpperCase();
}

let session = flow.get(sessionKey);
if (!session || session.active !== true) return null;

if (!session.currentCandidate || session.phase !== "wait_ack") {
    return null;
}

const currentCmd = cleanString(session.currentCandidate.command);
const msgCmd = cleanString(msg._raw_command || msg.command || msg._cmd || msg.payload?.raw_command || msg.payload?.command);

// message pas pour la commande actuellement testée
if (msgCmd !== currentCmd) return null;

// timeout remonté par Queue Pump
if (msg._learn_timeout === true || msg.payload?.timeout === true) {
    session.lastAck = "TIMEOUT";
    session.phase = "build";
    session.updatedAt = Date.now();

    flow.set(sessionKey, session);
    flow.set(pendingLearnKey, null);

    node.status({
        fill: "red",
        shape: "ring",
        text: `learn timeout ${session.param}`
    });

    return [null, {
        inverterNum: inv,
        _learn_action: "next_candidate"
    }];
}

const nak = (msg.payload?.nak === true);

if (nak) {
    session.lastAck = "NAK";
    session.phase = "build";
    session.updatedAt = Date.now();

    flow.set(sessionKey, session);
    flow.set(pendingLearnKey, null);

    node.status({
        fill: "yellow",
        shape: "ring",
        text: `learn NAK ${session.currentCandidate.key}`
    });

    return [null, {
        inverterNum: inv,
        _learn_action: "next_candidate"
    }];
}

// ACK ou réponse non-NAK => on force un QPIRI de vérification
session.lastAck = "ACK";
session.phase = "wait_state";
session.verifySentAt = Date.now();
session.updatedAt = Date.now();

flow.set(sessionKey, session);
flow.set(pendingLearnKey, {
    sessionId: session.sessionId,
    param: session.param,
    cmd: "QPIRI",
    phase: "wait_state",
    ts: Date.now()
});

const verifyMsg = {
    inverterNum: inv,
    command: "QPIRI",
    _cmd: "QPIRI",
    _raw_command: "QPIRI",
    payload: "QPIRI",
    _burst: false,
    _origin: "learn_retry",
    _learn: {
        sessionId: session.sessionId,
        param: session.param,
        requestedValue: session.requestedValue,
        candidateKey: session.currentCandidate.key,
        phase: "verify"
    }
};

node.status({
    fill: "blue",
    shape: "dot",
    text: `learn verify ${session.currentCandidate.key}`
});

return [verifyMsg, null];

// ====== LEARNING - BUILD CANDIDATE ======
// Sortie 1 = queue enqueue
// Sortie 2 = complete fail

const inv = msg.inverterNum ?? 1;

function getParallelId(inv) {
    let machine = flow.get(`inv${inv}_parallel_id`);
    if (machine === undefined || machine === null || machine === "") machine = 0;
    machine = Number(machine);
    if (!Number.isFinite(machine) || machine < 0 || machine > 9) machine = 0;
    return machine;
}

function pad3(x) {
    return String(Math.trunc(Number(x))).padStart(3, "0");
}

function fixed1(x) {
    return Number(x).toFixed(1);
}

function getRegistry(inv) {
    const machine = getParallelId(inv);

    return {
        battery_bulk_voltage: {
            kind: "number",
            candidates: [
                { key: "BULK_PCVV_1DEC", build: (v) => `PCVV${fixed1(v)}` }
            ]
        },
        battery_float_voltage: {
            kind: "number",
            candidates: [
                { key: "FLOAT_PBFT_1DEC", build: (v) => `PBFT${fixed1(v)}` }
            ]
        },
        battery_under_voltage: {
            kind: "number",
            candidates: [
                { key: "UNDER_PSDV_1DEC", build: (v) => `PSDV${fixed1(v)}` }
            ]
        },
        battery_recharge_voltage: {
            kind: "number",
            candidates: [
                { key: "BACK_TO_GRID_PBCV_1DEC", build: (v) => `PBCV${fixed1(v)}` }
            ]
        },
        battery_re_discharge_voltage: {
            kind: "number",
            candidates: [
                { key: "BACK_TO_BATTERY_PBDV_1DEC", build: (v) => `PBDV${fixed1(v)}` }
            ]
        },
        max_charging_current: {
            kind: "number",
            candidates: [
                { key: "MAX_CHG_MNCHGC_MACHINE", build: (v) => `MNCHGC${machine}${pad3(v)}` },
                { key: "MAX_CHG_MNCHGC_RAW", build: (v) => `MNCHGC${pad3(v)}` }
            ]
        },
        max_ac_charging_current: {
            kind: "number",
            candidates: [
                { key: "GRID_CHG_MUCHGC_MACHINE", build: (v) => `MUCHGC${machine}${pad3(v)}` },
                { key: "GRID_CHG_MUCHGC_RAW", build: (v) => `MUCHGC${pad3(v)}` }
            ]
        },
        output_source_priority: {
            kind: "enum_profile",
            profiles: {
                pop_00_02: {
                    0: { command: "POP00", expectedCode: 0 },
                    1: { command: "POP01", expectedCode: 1 },
                    2: { command: "POP02", expectedCode: 2 }
                },
                pop_01_03: {
                    0: { command: "POP01", expectedCode: 1 },
                    1: { command: "POP02", expectedCode: 2 },
                    2: { command: "POP03", expectedCode: 3 }
                }
            }
        },
        charger_source_priority: {
            kind: "enum_profile",
            profiles: {
                pcp_00_02: {
                    0: { command: "PCP00", expectedCode: 0 },
                    1: { command: "PCP01", expectedCode: 1 },
                    2: { command: "PCP02", expectedCode: 2 }
                },
                pcp_01_03: {
                    0: { command: "PCP01", expectedCode: 1 },
                    1: { command: "PCP02", expectedCode: 2 },
                    2: { command: "PCP03", expectedCode: 3 }
                }
            }
        }
    };
}

const sessionKey = `learn_session_inv${inv}`;
const pendingLearnKey = `learn_pending_inv${inv}`;

let session = flow.get(sessionKey);
if (!session || session.active !== true) return null;

const registry = getRegistry(inv);
const cfg = registry[session.param];
if (!cfg) return null;

function buildFailMsg(reason) {
    return {
        inverterNum: inv,
        topic: `voltronic/${inv}/learning/status`,
        payload: {
            active: false,
            success: false,
            reason,
            param: session.param,
            requested_value: session.requestedValue ?? null,
            requested_slot: session.requestedSlot ?? null,
            fingerprint: session.fingerprint,
            finished_at: new Date().toISOString()
        },
        _learn_complete: true,
        _learn_success: false
    };
}

// -------------------------------------------------
// MODE NUMERIQUE
// -------------------------------------------------
if (session.kind === "number") {
    session.index = Number(session.index || -1) + 1;
    session.updatedAt = Date.now();

    if (session.index >= session.candidateKeys.length) {
        node.status({
            fill: "red",
            shape: "ring",
            text: `learn fail ${session.param}`
        });
        return [null, buildFailMsg("no_candidate_left")];
    }

    const wanted = session.candidateKeys[session.index];
    const candidate = cfg.candidates.find(c => c.key === wanted.key);

    if (!candidate || typeof candidate.build !== "function") {
        flow.set(sessionKey, session);
        return [{
            inverterNum: inv,
            _learn_action: "next_candidate"
        }, null];
    }

    const cmd = candidate.build(session.requestedValue);

    session.currentCandidate = {
        mode: "number",
        key: candidate.key,
        source: wanted.source,
        command: cmd,
        sentAt: Date.now()
    };

    session.phase = "wait_ack";
    session.lastAck = null;

    flow.set(sessionKey, session);
    flow.set(pendingLearnKey, {
        sessionId: session.sessionId,
        param: session.param,
        cmd: cmd,
        phase: "wait_ack",
        ts: Date.now()
    });

    const out = {
        inverterNum: inv,
        command: cmd,
        _cmd: cmd,
        _raw_command: cmd,
        payload: cmd,
        _burst: false,
        _origin: "learn_retry",
        _ha_param: session.paramRaw || session.param,
        _ha_value: session.requestedRaw,
        _learn: {
            sessionId: session.sessionId,
            param: session.param,
            requestedValue: session.requestedValue,
            candidateKey: candidate.key,
            source: wanted.source,
            phase: "candidate"
        }
    };

    node.status({
        fill: "yellow",
        shape: "dot",
        text: `learn try ${candidate.key}`
    });

    return [out, null];
}

// -------------------------------------------------
// MODE PROFIL ENUM
// -------------------------------------------------
if (session.kind === "enum_profile") {
    let found = null;

    while (true) {
        session.index = Number(session.index || -1) + 1;
        session.updatedAt = Date.now();

        if (session.index >= session.candidateProfiles.length) {
            node.status({
                fill: "red",
                shape: "ring",
                text: `learn fail ${session.param}`
            });
            return [null, buildFailMsg("no_profile_left")];
        }

        const wanted = session.candidateProfiles[session.index];
        const profile = cfg.profiles?.[wanted.profileKey];
        const slotCfg = profile?.[session.requestedSlot];

        if (slotCfg && slotCfg.command) {
            found = {
                wanted,
                profileKey: wanted.profileKey,
                command: String(slotCfg.command).trim().toUpperCase(),
                expectedCode: Number(slotCfg.expectedCode)
            };
            break;
        }
    }

    session.currentCandidate = {
        mode: "profile",
        profileKey: found.profileKey,
        source: found.wanted.source,
        command: found.command,
        expectedCode: found.expectedCode,
        requestedSlot: session.requestedSlot,
        sentAt: Date.now()
    };

    session.phase = "wait_ack";
    session.lastAck = null;

    flow.set(sessionKey, session);
    flow.set(pendingLearnKey, {
        sessionId: session.sessionId,
        param: session.param,
        cmd: found.command,
        phase: "wait_ack",
        ts: Date.now()
    });

    const out = {
        inverterNum: inv,
        command: found.command,
        _cmd: found.command,
        _raw_command: found.command,
        payload: found.command,
        _burst: false,
        _origin: "learn_retry",
        _ha_param: session.paramRaw || session.param,
        _ha_value: session.requestedRaw,
        _learn: {
            sessionId: session.sessionId,
            param: session.param,
            requestedSlot: session.requestedSlot,
            profileKey: found.profileKey,
            expectedCode: found.expectedCode,
            phase: "candidate"
        }
    };

    node.status({
        fill: "yellow",
        shape: "dot",
        text: `learn try ${found.profileKey}`
    });

    return [out, null];
}

return null;

// ====== LEARNING - STATE FEEDBACK ======
// Sortie 1 = complete success
// Sortie 2 = next candidate

const inv = msg.inverterNum ?? 1;
const sessionKey = `learn_session_inv${inv}`;
const pendingLearnKey = `learn_pending_inv${inv}`;

function getByPath(obj, path) {
    if (!obj || !path) return undefined;
    return path.split(".").reduce((acc, k) => acc && acc[k], obj);
}

function toNum(v) {
    const n = Number(v);
    return Number.isFinite(n) ? n : null;
}

function isEqual(a, b, tol) {
    const na = toNum(a);
    const nb = toNum(b);
    if (na == null || nb == null) return false;
    return Math.abs(na - nb) <= tol;
}

const session = flow.get(sessionKey);
if (!session || session.active !== true) return null;

const cmd = String(msg.command || msg._cmd || "").trim().toUpperCase();
if (cmd !== "QPIRI") return null;

if (session.phase !== "wait_state") return null;

const state = msg.payload || {};

// -------------------------------------------------
// MODE NUMERIQUE
// -------------------------------------------------
if (session.kind === "number") {
    const actualValue = getByPath(state, session.statePath);

    if (isEqual(actualValue, session.requestedValue, session.tolerance)) {
        flow.set(pendingLearnKey, null);

        const okMsg = {
            inverterNum: inv,
            topic: `voltronic/${inv}/learning/status`,
            payload: {
                active: false,
                success: true,
                param: session.param,
                candidate_key: session.currentCandidate?.key || null,
                command: session.currentCandidate?.command || null,
                requested_value: session.requestedValue,
                verified_value: actualValue,
                fingerprint: session.fingerprint,
                finished_at: new Date().toISOString()
            },
            _learn_complete: true,
            _learn_success: true
        };

        node.status({
            fill: "green",
            shape: "dot",
            text: `learn OK ${session.param}`
        });

        return [okMsg, null];
    }

    flow.set(pendingLearnKey, null);

    node.status({
        fill: "yellow",
        shape: "ring",
        text: `learn next ${session.param}`
    });

    return [null, {
        inverterNum: inv,
        _learn_action: "next_candidate"
    }];
}

// -------------------------------------------------
// MODE PROFIL ENUM
// -------------------------------------------------
if (session.kind === "enum_profile") {
    const actualCode = toNum(getByPath(state, session.statePath));
    const expectedCode = toNum(session.currentCandidate?.expectedCode);

    if (actualCode != null && expectedCode != null && actualCode === expectedCode) {
        flow.set(pendingLearnKey, null);

        const okMsg = {
            inverterNum: inv,
            topic: `voltronic/${inv}/learning/status`,
            payload: {
                active: false,
                success: true,
                param: session.param,
                profile_key: session.currentCandidate?.profileKey || null,
                command: session.currentCandidate?.command || null,
                requested_slot: session.requestedSlot,
                verified_code: actualCode,
                expected_code: expectedCode,
                fingerprint: session.fingerprint,
                finished_at: new Date().toISOString()
            },
            _learn_complete: true,
            _learn_success: true
        };

        node.status({
            fill: "green",
            shape: "dot",
            text: `learn OK ${session.param}`
        });

        return [okMsg, null];
    }

    flow.set(pendingLearnKey, null);

    node.status({
        fill: "yellow",
        shape: "ring",
        text: `learn next ${session.param}`
    });

    return [null, {
        inverterNum: inv,
        _learn_action: "next_candidate"
    }];
}

return null;

// ====== LEARNING - COMPLETE ======

const inv = msg.inverterNum ?? 1;
const sessionKey = `learn_session_inv${inv}`;
const pendingLearnKey = `learn_pending_inv${inv}`;

let session = flow.get(sessionKey);

if (!msg._learn_complete) {
    return null;
}

const success = (msg._learn_success === true);

function clone(obj) {
    return JSON.parse(JSON.stringify(obj || {}));
}

function uniqNums(arr) {
    const out = [];
    for (const v of (Array.isArray(arr) ? arr : [])) {
        const n = Number(v);
        if (Number.isFinite(n) && !out.includes(n)) out.push(n);
    }
    return out.sort((a, b) => a - b);
}

// -------------------------------------------------
// SUCCÈS
// -------------------------------------------------
if (success && session && session.active === true && session.fingerprint && session.param) {
    const all = clone(global.get("learned_commands") || {});
    if (!all[session.fingerprint]) all[session.fingerprint] = {};

    const prev = all[session.fingerprint][session.param] || {};

    // ---------- paramètres numériques ----------
    if (session.kind === "number" && session.currentCandidate?.key) {
        all[session.fingerprint][session.param] = {
            key: session.currentCandidate.key,
            learnedAt: Date.now(),
            successCount: Number(prev.successCount || 0) + 1,
            failCount: 0,
            lastValue: session.requestedValue,
            lastCommandExample: session.currentCandidate.command
        };
    }

    // ---------- paramètres profil ----------
    if (session.kind === "enum_profile" && session.currentCandidate?.profileKey) {
        const prevCodes = uniqNums(prev.provenCodes || []);
        const expectedCode = Number(session.currentCandidate.expectedCode);
        const newCodes = uniqNums([...prevCodes, expectedCode]);

        // confirmed seulement quand on a vu un code discriminant 0 ou 3
        const confidence = (newCodes.includes(0) || newCodes.includes(3))
            ? "confirmed"
            : "tentative";

        all[session.fingerprint][session.param] = {
            mode: "profile",
            profileKey: session.currentCandidate.profileKey,
            confidence,
            provenCodes: newCodes,
            learnedAt: Date.now(),
            successCount: Number(prev.successCount || 0) + 1,
            failCount: 0,
            lastSlot: session.requestedSlot,
            lastExpectedCode: expectedCode,
            lastCommandExample: session.currentCandidate.command
        };
    }

    global.set("learned_commands", all);
}

// -------------------------------------------------
// ÉCHEC
// -------------------------------------------------
if (!success && session && session.fingerprint && session.param) {
    const all = clone(global.get("learned_commands") || {});
    const fp = all[session.fingerprint] || {};
    const entry = fp[session.param];

    if (entry) {
        entry.failCount = Number(entry.failCount || 0) + 1;

        // après 3 échecs, on oublie l'apprentissage
        if (entry.failCount >= 3) {
            delete fp[session.param];
        }

        all[session.fingerprint] = fp;
        global.set("learned_commands", all);
    }
}

flow.set(pendingLearnKey, null);
flow.set(sessionKey, null);

const historyKey = `learn_history_inv${inv}`;
let hist = flow.get(historyKey);
if (!Array.isArray(hist)) hist = [];

hist.unshift({
    ts: Date.now(),
    success,
    kind: session?.kind || null,
    param: session?.param || msg.payload?.param || null,
    candidate_key: session?.currentCandidate?.key || msg.payload?.candidate_key || null,
    profile_key: session?.currentCandidate?.profileKey || msg.payload?.profile_key || null,
    command: session?.currentCandidate?.command || msg.payload?.command || null,
    requested_value: session?.requestedValue ?? msg.payload?.requested_value ?? null,
    requested_slot: session?.requestedSlot ?? msg.payload?.requested_slot ?? null,
    expected_code: session?.currentCandidate?.expectedCode ?? msg.payload?.expected_code ?? null,
    fingerprint: session?.fingerprint || msg.payload?.fingerprint || null
});

if (hist.length > 30) hist = hist.slice(0, 30);
flow.set(historyKey, hist);

node.status({
    fill: success ? "green" : "red",
    shape: success ? "dot" : "ring",
    text: success ? "learn saved" : "learn failed"
});

return msg;

// ====== LEARNING - PREPROCESS ======
// Sortie 1 = apprentissage
// Sortie 2 = bypass direct

const inv = msg.inverterNum ?? 1;

function cleanString(v) {
    return String(v ?? "").trim();
}

function toNum(x) {
    if (x == null) return null;
    if (typeof x === "string") {
        const s = cleanString(x);
        const m = s.match(/-?\d+(\.\d+)?/);
        if (!m) return null;
        x = m[0];
    }
    const n = Number(x);
    return Number.isFinite(n) ? n : null;
}

function getByPath(obj, path) {
    if (!obj || !path) return undefined;
    return path.split(".").reduce((acc, k) => acc && acc[k], obj);
}

function getFingerprint(state) {
    const model = cleanString(state?.diag?.model);
    const serial = cleanString(state?.diag?.serial);
    if (!model || !serial) return "";
    return `${model}|${serial}`;
}

function canonParam(p) {
    const map = {
        battery_bulk_voltage: "battery_bulk_voltage",
        battery_float_voltage: "battery_float_voltage",

        battery_cutoff_voltage: "battery_under_voltage",
        battery_under_voltage: "battery_under_voltage",

        back_to_grid_voltage: "battery_recharge_voltage",
