  identifiers: [`voltronic_inv_${inv}`],
  name: `Voltronic Inverter ${inv}`,
  manufacturer: "Voltronic",
  model: "Axpert/Voltronic"
};

// mémorise les topics config publiés pour pouvoir les supprimer plus tard
const publishedTopics = [];

// =======================
// Display mode helpers
// =======================
function isLegacyMode(mode) {
  return String(mode || "").startsWith("legacy");
}

function getOutputPriorityOptions(mode) {
  if (isLegacyMode(mode)) {
    return ["USB", "SUB", "SBU"];
  }
  return ["UtilitySolarBat", "SolarUtilityBat", "SolarBatUtility"];
}

function getOutputPriorityValueTpl(mode) {
  if (isLegacyMode(mode)) {
    return `{{ {'UtilitySolarBat':'USB','SolarUtilityBat':'SUB','SolarBatUtility':'SBU'}.get(${QPIRI}.get('output_source_priority', 'SolarBatUtility'), 'SBU') }}`;
  }
  return jDeep(`${QPIRI}.get('output_source_priority', 'SolarBatUtility')`);
}

function getChargerPriorityOptions(mode) {
  if (isLegacyMode(mode)) {
    return ["CSO", "SNU", "OSO"];
  }
  return ["Solar first", "Solar + Utility", "Only solar"];
}

function getChargerPriorityValueTpl(mode) {
  if (isLegacyMode(mode)) {
    return `{{ {'Solar first':'CSO','Solar + Utility':'SNU','Only solar':'OSO'}.get(${QPIRI}.get('charger_source_priority', 'Solar first'), 'CSO') }}`;
  }
  return jDeep(`${QPIRI}.get('charger_source_priority', 'Solar first')`);
}

// -----------------------
// Config builders
// -----------------------
function sensorCfg(objectId, name, unit, device_class, state_class, valueTpl, extra = {}) {
  const uid = `voltronic_${inv}_${objectId}`;
  const topic = `${HA_PREFIX}/sensor/${uid}/config`;

  const payload = {
    name,
    unique_id: uid,
    state_topic,
    availability_topic,
    payload_available: "online",
    payload_not_available: "offline",
    value_template: valueTpl,
    device,
    ...extra
  };

  if (unit) payload.unit_of_measurement = unit;
  if (device_class) payload.device_class = device_class;
  if (state_class) payload.state_class = state_class;

  publishedTopics.push(topic);
  return { topic, payload: JSON.stringify(payload), retain: true };
}

function selectCfg(objectId, name, options, valueTpl, commandTopic, extra = {}) {
  const uid = `voltronic_${inv}_${objectId}`;
  const topic = `${HA_PREFIX}/select/${uid}/config`;

  const payload = {
    name,
    unique_id: uid,
    state_topic,
    availability_topic,
    payload_available: "online",
    payload_not_available: "offline",
    value_template: valueTpl,
    command_topic: commandTopic,
    options,
    device,
    ...extra
  };

  publishedTopics.push(topic);
  return { topic, payload: JSON.stringify(payload), retain: true };
}

function numberCfg(objectId, name, unit, min, max, step, valueTpl, commandTopic, extra = {}) {
  const uid = `voltronic_${inv}_${objectId}`;
  const topic = `${HA_PREFIX}/number/${uid}/config`;

  const payload = {
    name,
    unique_id: uid,
    state_topic,
    availability_topic,
    payload_available: "online",
    payload_not_available: "offline",
    value_template: valueTpl,
    command_topic: commandTopic,
    unit_of_measurement: unit,
    min,
    max,
    step,
    mode: "box",
    device,
    ...extra
  };

  publishedTopics.push(topic);
  return { topic, payload: JSON.stringify(payload), retain: true };
}

function textCfg(objectId, name, commandTopic, extra = {}) {
  const uid = `voltronic_${inv}_${objectId}`;
  const topic = `${HA_PREFIX}/text/${uid}/config`;

  const payload = {
    name,
    unique_id: uid,
    command_topic: commandTopic,
    availability_topic,
    payload_available: "online",
    payload_not_available: "offline",
    mode: "text",
    device,
    ...extra
  };

  publishedTopics.push(topic);
  return { topic, payload: JSON.stringify(payload), retain: true };
}

function clearPublishedTopics() {
  const topics = flow.get(topicsKey) || [];
  if (!Array.isArray(topics) || topics.length === 0) return [];
  return topics.map(t => ({ topic: t, payload: "", retain: true }));
}

// =======================
// Si cet onduleur n'est pas activé
// =======================
if (!enabled) {
  let msgs = [];
  if (changed) {
    msgs = clearPublishedTopics();
    flow.set(topicsKey, []);
    flow.set(lastSigKey, signature);
  }
  return [msgs];
}

