  )
];

let msgs = [];

// 1) si config changée, effacer les anciens retained
if (changed) {
  msgs = msgs.concat(clearPublishedTopics());
}

// 2) republier le discovery de cet onduleur
msgs = msgs.concat(msgsSensors, msgsParams);

// 3) mémoriser
flow.set(lastSigKey, signature);
flow.set(topicsKey, publishedTopics);

return [msgs];

// =======================
// MQTT DISCOVERY - VOLTRONIC (SAFE TEMPLATES)
// VERSION PAR ONDULEUR
// Compatible serial + gateway/tcp
//
// A CHANGER SELON LE NOEUD :
//   const inv = 1;   -> onduleur 1
//   const inv = 2;   -> onduleur 2
//   const inv = 3;   -> onduleur 3
